-- ----------------------------
--  Table structure for pay_bill
-- ----------------------------
DROP TABLE IF EXISTS "public"."pay_bill";
CREATE TABLE "public"."pay_bill" (
	"id" int8 NOT NULL DEFAULT nextval('pay_bill_id_seq'::regclass),
	"money" varchar(20) COLLATE "default",
	"pay_status" int2,
	"pay_time" char(14) COLLATE "default",
	"uid" char(36) COLLATE "default",
	"pay_way" int2,
	"update_time" char(14) COLLATE "default",
	"create_time" char(14) DEFAULT to_char(now(), 'YYYYMMDDHH24MISS'::text) COLLATE "default",
	"sub_time" char(14) COLLATE "default",
	"del_flg" int2 DEFAULT 0
)
WITH (OIDS=FALSE);
ALTER TABLE "public"."pay_bill" OWNER TO "postgres";

COMMENT ON COLUMN "public"."pay_bill"."money" IS '缴费金额';
COMMENT ON COLUMN "public"."pay_bill"."pay_status" IS '是否缴费成功:0-未审核；1-缴费成功；2-缴费失败；';
COMMENT ON COLUMN "public"."pay_bill"."pay_time" IS '哪期党费缴纳';
COMMENT ON COLUMN "public"."pay_bill"."uid" IS '用户id:user_info.uid';
COMMENT ON COLUMN "public"."pay_bill"."pay_way" IS '缴费方式:0-现金；1-在线缴纳；';
COMMENT ON COLUMN "public"."pay_bill"."update_time" IS '修改时间';
COMMENT ON COLUMN "public"."pay_bill"."sub_time" IS '递交党费日期';

-- ----------------------------
--  Records of pay_bill
-- ----------------------------
BEGIN;
COMMIT;

