INSERT INTO "public"."information" VALUES ('229', '内蒙古自治区直属机关2018年党的工作会议召开', null, '<p style="white-space: normal;"><span style="color: rgb(0, 0, 0);"><strong>原标题：自治区直属机关2018年党的工作会议召开</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><img src="http://localhost:8072/ueditor/jsp/upload/image/20180323/1521791225543073403.jpg"/></strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　3月19日，内蒙古自治区直属机关2018年党的工作会议召开，自治区党委常委、秘书长，直属机关工委书记罗永纲出席会议，他代表自治区党委和直属机关工委向全区机关党建工作者表示慰问和衷心感谢，并发表讲话；自治区直属机关工委常务副书记高慧广主持会议并作工作报告,自治区党委组织部部务委员史良同志到会指导,自治区直属机关工委副书记王君、狄瑞珍，自治区直属机关纪工委书记方瑛，自治区直属机关工委副巡视员韦占飞出席会议,自治区各部委办厅局机关党委、纪委和盟市直属机关工委负责人及自治区直属机关工委全体党员干部共300多人参加了会议。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这次会议的主要任务是以习近平新时代中国特色社会主义思想为指导，贯彻落实党中央决策和自治区党委工作部署，以新时代党的建设总要求为统领，全面贯彻党的十九大和十九届二中、三中全会和习近平总书记参加十三届全国人大一次会议内蒙古代表团审议时的重要讲话精神，以及自治区党委十届三次、四次、五次全委会议精神，深入落实党的建设、党风廉政建设、意识形态工作主体责任，把党的政治建设摆在首位，不断提高党的建设质量，全面总结2017年自治区直属机关党的工作，安排部署2018年工作。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><img src="http://localhost:8072/ueditor/jsp/upload/image/20180323/1521791225587032077.jpg"/></strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　罗永纲强调，区直机关各级党组织要牢牢把握深入学习贯彻习近平新时代中国特色社会主义思想和党的十九大精神这个主题主线，把握精髓实质、做好融会贯通，不断把学习贯彻习近平总书记参加十三届全国人大一次会议内蒙古代表团审议时的重要讲话精神引向深入。要牢牢把握新时代党的建设总要求，高质量发挥好政治建设的统领作用，抓好以党支部为核心的基层党组织建设，做到围绕中心、服务大局，持续推进正风肃纪工作，不断开创新时代机关党建工作新局面。要牢牢牵住压实责任这个“牛鼻子”，切实加强组织领导，着力形成机关党建齐抓共管的工作格局，努力为“建设亮丽内蒙古，共圆伟大中国梦”作出新的更大贡献。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><img src="http://localhost:8072/ueditor/jsp/upload/image/20180323/1521791225637008264.jpg"/></strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　高慧广回顾总结了2017年自治区直属机关党的工作，安排部署了2018年的工作任务，并就贯彻落实这次会议精神提出三点要求：一是与会同志要把这次会议精神，特别是罗永纲同志的重要讲话精神及时向党组（党委）汇报，研究提出贯彻落实会议精神的措施。二是机关党委的同志要认真学习研究会议精神，结合本单位实际，安排好今年机关党的工作，抓好各项工作任务的落实。三是机关党委要把会议精神传达到所属基层党组织，把会议确定的任务和主要工作要求传达到全体党员。要按照中央和自治区党委的要求，按照罗永纲同志的重要讲话精神，扎实推进机关党的工作。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　又讯：3月19日，自治区直属机关工委召开座谈会，与全区各盟市直属机关工委书记进行了座谈交流。自治区直属机关工委常务副书记高慧广主持会议，自治区直属机关工委副书记王君、狄瑞珍，自治区直属机关工委副巡视员韦占飞出席座谈会，工委各部门负责同志参加了座谈会。座谈会上，各盟市直属机关工委负责人围绕如何落实党的建设、党风廉政建设、意识形态工作主体责任、机关党建工作如何服务中心、建设队伍，怎样开展“不忘初心、牢记使命”主题教育，实施好“北疆先锋”工程，深化好“双建双创”活动，抓好机关党委建设和党支部标准化建设，提高机关党的建设质量，开创“活力党建”新局面进行了广泛深入的座谈交流，并汇报交流了各盟市直属机关党的工作典型经验和做法，明确了今年的工作重点。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><img src="http://localhost:8072/ueditor/jsp/upload/image/20180323/1521791225688042641.jpg"/></strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　会议要求，要把党的建设摆在首要位置，坚决维护以习近平同志为核心的党中央权威和集中统一领导，把学习贯彻习近平新时代中国特色社会主义思想作为党的建设根本任务，深入学习贯彻党的十九大精神，树牢“四个意识”。要进一步落实意识形态工作责任，加强宣传思想工作，充分发挥党内学习的理论武装和政治教育功能，推进机关精神文明建设。要着力提高机关党的建设质量，全面加强组织建设。开展“不忘初心，牢记使命”主题教育，推进“两学一做”学习教育常态化制度化，实施“北疆先锋”工程，加强“互联网+党建”工作，努力开创机关“活力党建”新局面。</strong></span></p><p><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '内蒙古自治区直属机关2018年党的工作会议召开', null, null, null, null, '20180323154719', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '1', '1', '1', '1', '1', null, '20180323154719', null, '20180323173754', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('225', '共产党讲的是另一种人情——毛泽东、毛岸英致亲人的两封信', null, '<p style="white-space: normal;"><span style="color: rgb(0, 0, 0);"><strong>原标题：共产党讲的是另一种人情</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><img src="http://localhost:8072/ueditor/jsp/upload/image/20180323/1521790814813065572.jpg"/><img src="http://localhost:8072/ueditor/jsp/upload/image/20180323/1521790814903047011.jpg"/></strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　编者按：习近平总书记在第一届全国文明家庭表彰大会上强调，家风是社会风气的重要组成部分。家风好，就能家道兴盛、和顺美满；家风差，难免殃及子孙、贻害社会。每一个家庭都要弘扬优良家风，以千千万万家庭的好家风支撑起全社会的好风气。特别是各级领导干部要带头培育好家风，继承和弘扬革命前辈的红色家风，做家风建设的表率。家书是体现家风的一面镜子，可以照出信仰、理想和追求。毛泽东于1949年10月9日写给杨开慧胞兄杨开智的信、后来毛岸英写给其表舅向三立的信（选自《红书简》，中共中央文献研究室、中央档案馆编，山西人民出版社2001年9月版），60多年后读来依然让人深深感受到共产党人的崇高情怀，值得我们认真品读。<br/><br/>毛泽东致杨开智</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>长沙上营盘街三十号杨开智先生：</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　希望你在湘听候中共湖南省委分配合乎你能力的工作，不要有任何奢望，不要来京。湖南省委派你什么工作就做什么工作，一切按正常规矩办理，不要使政府为难。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>毛泽东</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>十月九日</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>&nbsp;</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>毛岸英致向三立</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>三立同志：</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　来信收到。你们已参加革命工作，非常高兴。你们离开三福旅馆的前一日我曾打电话与你们，都不在家，次日再打电话时，旅馆职员说你们已经搬走了。后接到林亭同志一信，没有提到你们的“下落”。本想复他并询问你们在何处，却把他的地址连同信一齐丢了（误烧了）。你们若知道他的详细地址望告。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　来信中提到舅父“希望在长沙有厅长方面位置”一事，我非常替他惭愧。新的时代，这种一步登高的“做官”思想已是极端落后的了，而尤以为通过我父亲即能“上任”，更是要不得的想法。新中国之所以不同于旧中国，共产党之所以不同于国民党，毛泽东之所以不同于蒋介石，毛泽东的子女妻舅之所以不同于蒋介石的子女妻舅，除了其他更基本的原因以外，正在于此：皇亲贵戚仗势发财，少数人统治多数人的时代已经一去不返了。靠自己的劳动和才能吃饭的时代已经来临了。在这一点上，中国人民已经获得了根本的胜利。而对于这一层舅父恐怕还没有觉悟。望他慢慢觉悟，否则很难在新的中国工作下去。翻身是广大群众的翻身，而不是几个特殊人物的翻身。生活问题要整个解决，而不可个别解决。大众的利益应该首先顾及，放在第一位。个人主义是不成的。我准备写封信将这些情形坦白告诉舅父他们。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　反动派常骂共产党没有人情，不讲人情，如果他们所指的是这种帮助亲戚朋友、同乡同事做官发财的人情的话，那么我们共产党正是没有这种“人情”，不讲这种“人情”。共产党有的是另一种人情，那便是对人民的无限热爱，对劳苦大众的无限热爱，其中也包括自己的父母子女亲戚在内。当然，对于自己的近亲，对于自己的父、母、子、女、妻、舅、兄、弟、姨、叔是有一层特别感情的，一种与血统、家族有关的人的深厚感情的。这种特别感情，共产党不仅不否认，而且加以巩固并努力于倡导它走向正确的与人民利益相符合的有利于人民的途径。但如果这种特别感情超出了私人范围并与人民利益相抵触时，共产党是坚决站在后者方面的，即“大义灭亲”亦在所不惜。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　我爱我的外祖母，我对她有深厚的描写不出的感情，但她也许现在在骂我“不孝”，骂我不照顾杨家，不照顾向家，我得忍受这种骂，我决不能也决不愿违背原则做事。我本人是一部伟大机器的一个极普通平凡的小螺丝钉，同时也没有“权力”，没有“本钱”，更没有“志向”，来做这些扶助亲戚高升的事。至于父亲，他是这种做法最坚决的反对者，因为这种做法是与共产主义思想、毛泽东思想水火不相容的，是与人民大众的利益水火不相容的，是极不公平，极不合理的。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　无产阶级的集体主义——群众观点与资产阶级的个人主义——个人观点之间的矛盾正是我们与舅父他们意见分歧的本质所在。这两种思想即在我们脑子里也还在尖锐斗争着，只不过前者占了优势罢了。而在舅父的脑子里，在许多其他类似舅父的人的脑子里，则还是后者占着绝对优势，或者全部占据，虽然他本人的本质可能不一定是坏的。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　关于抚恤烈士家属问题，据悉你的信已收到了。事情已经转组织部办理，但你要有精神准备：一下子很快是办不了的。干部少事情多，湖南又才解放，恐怕会拖一下。请你记住我父亲某次对亲戚说的话：“生活问题要整个解决，不可个别解决。”这里所指的生活问题主要是指经济困难问题，而所谓整个解决主要是指工业革命、土地改革、统一的烈士家属抚恤办法等，意思是说应与广大的贫苦大众一样地来统一解决生活困难问题，在一定时候应与千百万贫苦大众一样地来容忍一个时期，等待一个时期，不要指望一下子把生活搞好，比别人好。当然，饿死是不至于的。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　你父亲写来的要求抚恤的信也收到了。因为此事经你信已处理，故不另复。请转告你父亲一下并代我问候他。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　你现在可能已开始工作了罢。望从头干起，从小干起，不要一下子就想负个什么责任。先要向别人学习，不讨厌做小事，做技术性的事，我过去不懂这个道理，曾经碰过许多钉子，现在稍许懂事了——即是说不仅懂得应该为人民好好服务，而且开始稍许懂得应该怎样好好为人民服务，应该以怎样的态度为人民服务了。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　为人民服务说起来很好听，很容易，做起来却实在不容易，特别对于我们这批有小资产阶级个人英雄主义的，没有受过斗争考验的知识分子是这样的。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　信口开河，信已写得这么长，不再写了。有不周之处望谅。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　祝你健康！</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>岸英 上</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>10月24日</strong></span></p><p><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '共产党讲的是另一种人情——毛泽东、毛岸英致亲人的两封信', null, null, null, null, '20180323154029', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '1', '1', '1', '1', '1', null, '20180323154029', null, '20180323174217', '1', '0', null, '0', null, null, null, null, null);
