INSERT INTO "public"."information" VALUES ('177', '王文涛任黑龙江省委副书记(图/简历)', null, '<p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; font-family: 微软雅黑; line-height: normal;"><span style="font-size: 16px; color: rgb(0, 0, 0);">中国共产党新闻网北京3月23日电 &nbsp; (记者姚茜)据《黑龙江日报》消息，中共中央批准：王文涛同志任黑龙江省委委员、常委、副书记。陆昊同志不再担任黑龙江省委副书记、常委、委员职务。</span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; font-family: 微软雅黑; line-height: normal;"><span style="font-size: 16px; color: rgb(0, 0, 0);">王文涛同志简历</span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; font-family: 微软雅黑; text-align: center; line-height: normal;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><img alt="王文涛.jpg" src="http://scgh.gobestsoft.com:18080/ueditor/jsp/upload/image/20180323/1521786511457031725.jpg"/></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; font-family: 微软雅黑; line-height: normal;"><span style="font-size: 16px; color: rgb(0, 0, 0);">王文涛，1964年5月生，江苏南通人。复旦大学哲学系哲学专业毕业，大学，工商管理硕士，副教授。1994年12月加入中国共产党。1985年7月参加工作。先后在上海航天职工大学团委、学生科工作。1992年6月起，历任上海航天职工大学学历教育科科长、复印机销售部副总经理，上海航天职工大学校长助理、复印机销售部总经理，上海航天职工大学副校长，上海市松江区发展计划委主任。2002年1月任上海市松江区副区长。2005年1月起任云南省昆明市委副书记，代市长、市长。2007年6月起任上海市黄浦区委副书记，代区长、区长。2008年2月任上海市黄浦区委书记、区长。2008年6月任上海市黄浦区委书记。2011年4月任江西省委常委、南昌市委书记。2015年3月任山东省委常委、济南市委书记。2017年3月任省委副书记、济南市委书记。2017年4月任省委副书记兼省委党校校长，济南市委书记。2017年6月在中共山东省第十一届委员会第一次全体会议上当选为省委副书记。2018年3月任黑龙江省委委员、常委、副书记。</span></p><p><br/></p>', '王文涛任黑龙江省委副书记(图/简历)', null, null, null, null, '20180323142845', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '14', '1', '1', '1', '1', null, '20180323142703', null, '20180424145845', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('218', '申纪兰：人民代表就要代表人民', null, '<p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>远远地看见记者，申纪兰甩开搀扶人的手，张开双臂迎了上来。进屋后，问一声“冷不冷”，又边摸兜边问“抽不抽烟？我专门拿了烟”。寒冷的冬天，碰到这位热情的老人，顿时心中觉得一暖。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>申纪兰已89岁高龄了。老人坐在阳光里，脸上的每道皱纹都是不朽的岁月痕迹。她身后的墙上，挂满了照片，有集体照、有单独照，得空的时候，她总是用手擦拭着照片上的灰尘，像是在细细回味自己的一生。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>碱大馒头吃得香，伸手就敢掰腕子</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>冬日的太行山深处，阳光洒进沟里头。寒山上的树木在低温里倔强挺立着，远处岭下的积雪兀自雪白，道旁是一串串挂鞭炸裂后的红色，背后升起一片炊烟袅袅。在这个安静祥和的北方新年里，趁着中午的暖和劲，村里的人三三两两地走出来，在村头边晒太阳边聊天。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>申纪兰远远地走了过来，大家伙不约而同地打起了招呼：“过年好！”老人边招手边坐到了众人之间：“老李，你这腿咋样了？”“多亏你帮忙，刚做了手术，没啥大事情了！”老人欣慰地点点头。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>这些熟悉的邻里乡亲，是她一生放不下的牵挂。谁家有个红白喜事，她都是“总管”的角色，谁家碰到个得病、修房的，也来找她帮忙。就像一位邻家老大姐，村民们有事情就来找她唠一唠。他们都知道，老大姐人好、爱聊天、能“做主”。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>她是个“很讲究”的人。经常陪她外出的张娟说：“我们在外住宾馆，她会早早地起床，把床铺收拾得干干净净。我说，让服务人员来收拾就好了，但是她总说不要给人家添麻烦。在她的带动下，我们现在住宾馆都是自己把床铺收拾利索。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>她是个“不讲究”的人。一次，一位知名导演来看她，在乡里饭店吃饭，点了馒头，结果这馒头“碱大了”，导演觉得很不应该，担心她吃不惯。等回头一看，老人毫不在意，正自顾自地吃得香着咧。“我就是个农民，没那么多讲究。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>除了热情、质朴，申纪兰性格中更透着一股不服输的韧劲。老人身体硬朗，腿脚也算利索，就是不能长时间走路。前几年，隔壁村着了火，老人爬到山头上去看火情，不小心摔了一下。养了几个月，村头很快又出现她的身影。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“每年10万多游客，不少来了想见见我。”每天要见很多人，常人都会觉得累，但申纪兰总是把最好的状态展现给来访者。不服输的她突然提出要和记者掰腕子：“你们觉得我老了？试试我这手劲。”记者用尽全力，掰了个平手。她哈哈一笑：“当年带着全村人下地干活，我和村里的男劳力比赛，受的苦比这重多了，我都没输。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1952年，申纪兰担任农社副社长，村里男女参加农社活动。当时女劳力挣的工分是“老五分”，不管干多少，都是五分，而男劳力能挣十分。她不服输，提出进行劳动比赛，男女同工同酬，男劳力“踩犁”“匀粪”，她也能干，而且干得比有的男劳力还好。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>一个甲子过去了，每年的人代会她都带着自己关心的“三农”议案参加，她也因此被称为全国人大代表制度的“常青树”。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>人民代表，就要代表人民的利益</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>当年刚知道自己选上人大代表的时候，申纪兰还有点不敢相信。第一次从平顺县去北京开人代会，乡里给她找了头毛驴，但是大山里坡太陡，石头山上的小路，让第一次出远门的她吓得不敢骑。去了长治，又从长治倒“班车”去太谷，再从太谷坐火车到太原，辗转到北京，耗时好几天。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>64年来，平顺到北京的路线她每年都要走，春夏秋冬、来来回回。她也越走越明白，“人民代表就要代表人民的利益，要是代表自己，就不是人民代表了。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>上世纪80年代，当上山西省妇联主席这个“厅官”的时候，申纪兰提出“六不”：不转户口、不定级别、不领工资、不要住房、不调工作关系、不脱离劳动。当时在省城太原，有机会分房子，她也拒绝了：“还是睡办公室好，开会的时候折叠床一收，办公休息两不误。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>申纪兰不仅是个质朴坦率、真实可亲的乡亲，还是一个甘于奉献，集体荣誉感极强的不寻常女性。一穷二白的西沟，靠着集体产业大步前行在致富路上，“领头雁”的申纪兰功不可没。“当年我们这是‘石头山石头沟，谁干也发愁’，种树没钱买树苗，就是直接撒籽，虽然成活率低，但最终还是绿化了。这种不畏艰难、艰苦奋斗的精神，被称作‘纪兰精神’。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>改革开放之后，西沟又率先搞发展。“闯市场难道说比当年石头上栽树还难？”村里刚开始办企业的时候，申纪兰带人外出考察，舍不得花村里的一分钱吃碗面，几个人硬生生在外跑了一天，回来才生火造饭。时代在变，但申纪兰身上艰苦奋斗的精神没有变。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>这些年，西沟村的集体经济发展得很好，站在半山腰上，就能看到山下一排排的大棚，还引入了“太子龙”服装厂加工车间，形成了以核桃露、小杂粮为主的绿色产业，和以“纪兰”“西沟”名人名村为品牌的红色旅游产业。核桃露厂用她的名字命名，企业商量给她一点“冠名费”，被她拒绝。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>在申纪兰家的屋里正聊着，院子里突然“砰”的一声。工作人员帮申纪兰捡了起来，是一摞塑料纸包着的材料。申纪兰并不奇怪，她说，每年都有全国各地的人来找她“反映问题”，甚至有人要当她的“干女儿”。申纪兰说：“不用这样，我是人大代表，你如果真有问题，我肯定帮你反映。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“今年的两会和过年时间挨得近。”过年了，申纪兰也没闲着，加班加点准备议案。她的议案多年来一直关注着农村，山区交通建设、保护耕地、新型农村合作医疗、农村干部选举、贫困地区旅游开发等，一条条凝聚她心血汗水的建议，不断得到采纳和兑现。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>从当初的“不识字”，到现在轻松读报、调研形成议案，人大代表这个身份倒逼申纪兰不断进步。60多年，她见证了人大制度的不断完善。“人大的地位越来越高，调研、监督不搞虚，还成立了中国人民代表大会制度理论研究会、组建人大代表小组，人民代表大会制度不断与时俱进。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>爱党爱国，已成为心中的信仰</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>对于集体，她倾尽全部；对于党和国家，她有质朴的情感和真诚的信仰。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“我文化低，就是和党有深感情。”申纪兰从旧时代过来，对中国共产党有着深深的情感。当年参加第一届人民代表大会，住在北京东四的小旅馆里，《人民日报》记者来采访她，问她最想说的是什么，她局促地搓着双手，问了一句“能不能见到毛主席？”后来的事情，她都没敢想，毛泽东主席亲自接见过她，周恩来总理还请她和妇女代表们吃饭。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>那面墙上的显眼位置，还有她和乡亲们与习近平总书记的合影。那是2009年，习近平去西沟探望了申纪兰，在村头和乡亲们留下一张珍贵照片。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>谈到现在，老人激动得直竖大拇指，一连几个“好”。“现在习近平总书记倡导的‘一带一路’，世界很多国家都加入了，好啊！中国有了顶梁柱，党中央有了主心骨。”老人边说边乐：“本来我还想去总书记待过的梁家河看看，结果还没去成，前几天梁家河的村支书就来看我了，还给我带了梁家河产的苹果。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>西沟村曾经办过铝合金厂，发展得不错，但因为污染比较严重，环保压力很大。效益和问题都摆在那里，到底关还是不关，村里人争议很大。“现在都在讲转型，我们厂子污染严重，不符合中央和国家的政策，只要是和大政方针相违背的，我们坚决不做！”申纪兰一锤定音。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>十九大刚结束那几天，晚上不忙的时候，申纪兰就认真学习十九大报告。几个大本上密密麻麻地记录着她的成果，那是她在台灯下一笔一画抄出来的。“党员说话行动要保持一致，不学习怎么保持一致？”她说。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>老当益壮，宁移白首之心。一个甲子过去了，议案内容有变化，而不变的是“申大姐”的齐耳短发、深蓝布衣。直到现在，老人依然每年春天不忙的时候，去她的几分地里挥锄种苗。她没钱吗？不是。她在用行动告诉人们，她时刻没有忘记初心，也在提醒自己，生活再美好，也不能忘掉艰苦奋斗的岁月！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>两年前，长治市“长治好人”颁奖晚会，邀请她去做颁奖嘉宾。当天，大雪封山，太行山被蒙上厚厚银装。长治市委市政府考虑到交通不便，同意老人可不去。老人把手一挥：“党和人民需要我，再难我也去！”当天，老人冒雪穿过山路去颁奖。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>那个雪夜，那条山路，见证了她的执着和坚定；爱党爱国，已成为申纪兰心中的信仰。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 0); text-indent: 2em; display: block;">《 人民日报 》（ 2018年03月02日 10 版）</span></strong></span></p><p><br/></p>', '申纪兰：人民代表就要代表人民', null, null, null, null, '20180323153125', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '1', '0', '2', '1', '1', '1', '1', null, '20180323153125', null, '20180323172345', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('219', '河南项城“微党课”：支部是学校人人是教员', null, '<p style="white-space: normal;"><span style="color: rgb(0, 0, 0);"><strong>原标题：河南项城“微党课”：支部是学校人人是教员</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“党的十九大报告提出了‘乡村振兴战略’‘建设美丽中国’，正视了城乡之间发展不均衡不充分的现实，乡村振兴和建设美丽乡村正逢其时。我们现在进行的美丽乡村建设完全符合十九大精神要求，建设生态孙店、打造新亮点、树立新形象是全镇干部群众的共同愿望。”2月1日，河南省项城市孙店镇党委书记徐启华在“微党课”上的一席话，坚定了台下全镇34个行政村党支部书记搞好美丽乡村建设的决心和信心。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“微党课”是项城市以召开微小型会议的形式，贯彻落实党的十九大精神的必修课。“微党课”用鲜活的事例、通俗的语言、时尚的载体，打牢“学”的基础，突出“做”的关键，推动党的十九大精神落地生根，推动“两学一做”学习教育深入开展。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　孙店镇的“微党课”实行一天一课制度，每课下来半个小时，时间不长，灵活多样，效果明显。每名镇干部、行政村党支部书记、镇直站所负责人结合自身工作实际制作课件，每天领学党的十九大报告原文600字左右，参会人员结合实际谈学习体会。把学习的理论融入自身的事理当中，有事迹、有典型，有对比、有图说。“这种学习形式，我们最喜欢，也最容易理解接受。”龚堂村党支部书记龚建民说。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　为搞好十九大精神“微党课”宣讲，项城市组织部门专门为各级党员干部，特别是镇（办）干部、村党支部书记、镇直站所负责人印制了《党的十九大精神学习笔记》，人手一册，将党的十九大报告原文和决议编印到学习笔记当中，并按时间顺序、领导顺序，排好“微党课”课程表，要求每人精读原文、精心准备。各级党员干部在“微党课”讲授中，积极认真备课，让学员听到接地气的心得体会。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　为了让“微党课”走进百姓心间，该市把“微党课”授课现场前移，做到党员在哪里，“微党课”就设在哪里，创新开展“点菜式”“互动式”“模拟式”党课，增强“微党课”的感染力。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　身边人讲身边事，没有客套，有的是满满的干货；没有煽情，有的是盈盈的真情。正是在这样的氛围下，“微党课”听众的心被一次次叩动。项城市委书记刘昌宇说：“以小见大、见微知著的微党课，变一人讲为大家讲，变长篇大论为短小精悍，变单一型为多样化，变灌输式为互动式。”目前，项城市21个镇（办事处），86个市直单位，1100多个基层党组织，已开展“微党课”3600多场次，3000多名党员干部登台讲课，听课者近30万人次，在全市形成了“支部是学校、党员是学员、人人是教员”的良好氛围。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　 （记者 王胜昔 通讯员 闫晓红）</strong></span></p><p><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '河南项城“微党课”：支部是学校人人是教员', null, null, null, null, '20180323153218', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '1', '1', '1', '1', '1', null, '20180323153218', null, '20180323172322', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('180', '认真履行纪检监察职责 保证深化党和国家机构改革顺利进行', null, '<p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　人民网北京3月22日电&nbsp;&nbsp;（记者姜洁）中共中央纪委日前印发通知，要求各级纪检监察机关坚决贯彻党中央决策部署，认真履行纪检监察职责，加强对深化党和国家机构改革实施情况的监督检查，严肃查处改革中的违纪行为，以严肃问责推动改革主体责任落实，保证深化党和国家机构改革顺利进行。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党的十九大对深化机构改革作出重要决策部署，十九届三中全会审议通过了《中共中央关于深化党和国家机构改革的决定》和《深化党和国家机构改革方案》。深化党和国家机构改革是坚持和加强党的全面领导的必然要求，直接关系到国家治理体系的完善和治理能力的提升，对统筹推进“五位一体”总体布局和协调推进“四个全面”战略布局发挥着体制支撑和保障作用。各级纪检监察机关必须提高政治站位，在政治立场、政治方向、政治原则、政治道路上同党中央保持高度一致，把思想和行动统一到党中央决策部署上来。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　通知指出，纪检监察机关肩负着维护以习近平同志为核心的党中央权威和集中统一领导的特殊使命和重大责任，要把推进深化党和国家机构改革落实落地作为检验党性强不强、“四个意识”牢不牢的重要实践。认真履行党内监督专责机关职责，把加强对深化党和国家机构改革实施情况的监督检查作为一项重要任务来抓，精心组织，周密安排。督促各地区各部门全面准确贯彻习近平总书记重要讲话要求和党的十九届三中全会精神，确保党中央的决策部署落到实处。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　通知强调，纪检监察机关要在各级党委（党组）领导下，会同有关职能部门，严肃查处各项违反纪律问题。严明政治纪律，坚决查处有令不行、有禁不止，上有政策、下有对策，搞变通、拖延改革等问题，确保深化党和国家机构改革严格按照党中央部署有序实施。严明组织纪律，严格请示报告制度，坚决查处擅自行动、一哄而起，重大改革事项不及时报告等问题，确保中央和地方机构改革在工作部署、组织实施上有机衔接。严肃机构编制纪律，坚决查处机构改革方案涉及的机构设置、人员编制调整不按规定程序报批，擅自提高机构规格、调整和增设内设机构、增加人员编制和领导职数，在编制数据上弄虚作假，上级业务主管部门违反规定干预下级机构设置和编制配备等问题。严肃干部人事纪律，坚决查处违反民主集中制原则和干部工作程序规定擅自决定涉及人员分流、干部任免等重大事项，突击进人、突击提拔和调整交流干部、突击评定专业技术职称，拒不执行组织作出的机构调整、职位变动和干部交流决定等问题。严肃财经纪律，坚决查处漏报、瞒报、隐匿和违规处置国有资产，造成国有资产流失，隐瞒、挪用资金或虚列支出，转移套取资金，突击花钱、巧立名目发放和私存私放钱物，以及违反中央八项规定精神等问题。严格保密纪律，坚决查处泄露党和国家秘密、传播小道消息等问题。对发现的违纪问题，不管涉及谁，不管涉及多少人，都必须坚决查处，决不姑息迁就。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　通知要求，各级纪检监察机关要牢牢抓住深化党和国家机构改革主体责任这个“牛鼻子”，推动各级党委及其职能部门、政府及其职能部门党组（党委）充分发挥领导作用，把加强党对一切工作的领导贯穿深化党和国家机构改革各方面和全过程，确保深化党和国家机构改革方案顺利实施。中央纪委督促中央各部门和国家机关各部门党组（党委）、地方各级纪检监察机关督促同级党委职能部门和政府职能部门党组（党委）切实担负起主体责任，守土有责、守土尽责，坚决服从大局，坚决落实改革任务，确保机构职能等按要求及时调整到位。对失职失责、敷衍塞责的党组织、党员领导干部严肃问责，对情节严重、造成恶劣影响的从重处理，对该问责而不问责的也要严肃问责，典型案例一律通报曝光，推动形成一级抓一级、层层抓落实的良好局面。各级纪检监察机关要把自己摆进去、把职责摆进去，带头讲政治、顾大局、守纪律，坚决完成推进党的纪律检查体制和国家监察体制改革的各项任务，勇做改革的先锋和表率。</strong></span></p><p style="white-space: normal;"><br/></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　《 人民日报 》（ 2018年03月23日 04 版）</strong></span></p><p style="white-space: normal;"><br/></p><p><br/></p>', '认真履行纪检监察职责 保证深化党和国家机构改革顺利进行', null, null, null, null, '20180323143232', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '0', '1', '1', '1', '1', null, '20180323143232', null, '20180323171819', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('249', '第二届世界马克思主义大会进入倒计时100天', null, '<p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“在人类思想史上，没有一种思想理论能达到马克思主义的高度，也没有一种学说能像马克思主义那样对世界产生如此巨大的影响。”今年是马克思诞辰200周年、《共产党宣言》发表170周年、中国改革开放40周年，北京大学25日宣布，第二届世界马克思主义大会将于5月5日至6日在北京举行，距离现在还有100天，“这将是全世界马克思主义理论研究和科学社会主义伟大实践进程中具有里程碑意义的重大事件”，北京大学马克思主义学院执行院长孙熙国在新闻发布会上表示。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>深刻认识当今时代、世界格局和中国社会发展历史方位的新变化，继续推进马克思主义中国化时代化大众化，不断创新和发展21世纪马克思主义和21世纪中国的马克思主义，是马克思主义研究的重大时代课题。以“马克思主义与人类命运共同体”为主题的第二届世界马克思主义大会，将立足展现中国道路、中国理论、中国制度和中国文化的风貌和自信，直面当今国际社会面临的共同问题，研究阐释马克思主义，特别是习近平新时代中国特色社会主义思想，研究探讨中国经验和人类发展中的重大问题，汇聚世界各国马克思主义理论研究的领军人物，积极探讨凝聚共识，推动中国社会进步，引领世界文明发展。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>孙熙国说，新时代中国特色社会主义事业的成功实践和伟大发展，已成为当代世界知识界和社会各界关注的热点问题。在此背景下，再次举办世界马克思主义大会，有利于中外学者拓宽马克思主义研究视野，提升中国马克思主义研究的世界影响；有利于各国学者全面感受和认识中国的蓬勃发展，深入了解中国道路和中国马克思主义；有利于用中国话语向国际学界阐释中国道路、中国理论、中国经验，传播中国声音，提升中国的国际话语权，扩大中国的国际影响力。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>据悉，本次大会将设置纪念马克思诞辰200周年、马克思主义理论与文本研究、《马藏》编纂与研究、马克思主义与世界社会主义、习近平新时代中国特色社会主义思想与当代马克思主义等十个分论坛，以及中国方案与发展中国家现代化途径、新时代中国特色社会主义与21世纪世界社会主义等四个高端对话专场。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>记者了解到，作为北大校庆120周年活动的组成部分，第二届世界马克思主义大会还将举行纪念马克思诞辰200周年学术周、国际学者主题书展等系列活动。此外，世界马克思主义大会网站（wcm.pku.edu.cn）也在加紧建设中，拟于2月5日开始试运行。另据北大马克思主义学院副院长孙代尧介绍，2015年北大开始启动《马藏》的编纂，“不是简单的资料性文件复制影印，而是突出学术性、研究性的汇纂”。目前收集的资料从1871年巴黎公社成立到1917年传入中国的马克思主义文献，包括著作文本50多本，还有几百篇报刊文章，初步打算今年马克思主义大会期间出版5到6卷《马藏》，到年底出版10卷，每卷50万字。（记者晋浩天）</strong></span></p><p style="white-space: normal;"><span style="color: rgb(0, 0, 0);"><strong>(责编：杨丽娜、常雪梅)</strong></span></p><p><span style="color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '第二届世界马克思主义大会进入倒计时100天', null, null, null, null, '20180323161853', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '4', '1', '1', '1', '1', null, '20180323161852', null, '20180323173520', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('228', '江西新余国税局：党旗引领启新程 不忘初心铸税魂', null, '<p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>近年来，江西省新余市国税局党组以习近平新时代中国特色社会主义思想为指导，围绕“纵合横通强党建”工作思路，抓实创新党建铸魂，抓牢扛实主体责任，推动全面从严治党延伸到基层“神经末梢”，为推动国税各项事业发展提供了坚强的组织保障。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>一、聚焦机制创新，党建责任“落地生根”。按照“条主动、块为主”“下抓两级、抓深一层”党建工作机制要求，严格落实全面从严治党主体责任，始终把党建工作摆在重要位置。抓实制度建设。制定下发“全面从严治党工作要点”“全面从严治党主体责任清单”“党风廉政建设责任清单”等6个文件，明确责任部门、理清工作职责、汇聚党建合力。全系统配齐配强专职党务干部6名，兼职党务干部8名，充实了党建工作专门力量。扛实党建责任。牢牢牵住全面从严治党主体责任，去年市局分别召开4次党组会、5次机关党委扩大会、2次党建现场推进会，明确58项全面从严治党和64项党风廉政建设主体责任，市局班子成员和机关支部建立共联共建党建联系点16个，推动全面从严治党向基层延伸、向纵深发展。用实监督考核。召开县（区）局党组书记和机关党支部书记抓基层党建工作述职评议会，对基层党组书记抓党建工作“把脉会诊”“开出药方”，并将考评结果写入个人年度考核评价意见。组织开展全系统党建工作检查4次，持之以恒推动基层党建工作全面进步全面过硬。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>二、聚焦政治建设，党建载体“枝繁叶茂”。始终将加强政治建设摆在首要位置，坚持用习近平新时代中国特色社会主义思想武装头脑、指导实践、推动工作。深入学习贯彻党的十九大精神。在全市国税系统举办科级干部党的十九大精神专题研讨班，邀请市委常委、宣传部部长解读十九大精神，市局班子成员带头深入党建联系点宣讲十九大精神，帮助党员干部学懂弄通十九大精神。开展“学习十九大、我最赞的一句话”征集活动，举办“不忘初心、牢记使命”党的十九大知识竞赛，开展十九大理论考试、微信答题，引导党员干部读原著、学原文、悟原理。我局学习贯彻十九大精神经验做法得到省局国税党建专刊宣传推介。深入推进“两学一做”学习教育常态化制度化。各级党组织以中心组理论学习和“三会一课”制度为主要形式，围绕“四讲四有”专题开展学习研讨，市局机关共查摆问题99个，分别制定整改措施，并已全面整改到位。在全市国税系统开展“讲政治、守纪律、重规矩、作示范”主题教育，通过学党规、查问题、促整改、建制度，有效解决了系统内少数单位和党员干部存在的党性不强、规矩不严、担当不够等突出问题。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>三、聚焦融合发展，党建品牌“开花结果”。重点打造的三区三亮色（即国地税联合党建示范区、纳税服务党建示范区、流动党员管理示范区；三个对话“红色”教育、党群连心“绿色”通道、先锋党员“金色”标杆）党建特色品牌，得到省局和市委领导批示肯定，《江西税务》刊登推荐了经验做法。联合党建走在前头。在分宜县国税局建立全省首个国地税联合党支部，又在高新区国地税局组建了全省首个联合党总支，截至去年8月份，全市所有办税服务厅实现了联合党建全覆盖。国地税联合党组织成立后，双方组织联建、学习联动、活动联创，去年“七一”，国地税联合在市广播电视台演播大厅举办“聚合力共谋税收发展、勇担当争做合格党员”“两学一做”党建知识竞赛，在全市引起了强烈反响。此外，国地税双方联合开展“主题党日”，携手共办篮球友谊赛、足球联赛等文体活动，推动了国地税深度融合，获评“全国百佳国地税合作市级示范区”。党建融合干在前头。以创建“共产党员示范市”为契机，以开展“提升执行力、党员作表率”主题活动为载体，在全市率先创建“龚全珍工作室”，传承红色基因，宣讲政策法规，倾情服务群众，将党建有机融入纳税服务，打造具有鲜明税务特色的“便民税务”品牌，一年来，龚全珍工作室帮助纳税人解决涉税问题400余个，实现税收服务“零距离”。第一直属税务分局办税服务厅荣获“全国三八红旗集体”“全国青年文明号”等荣誉，全市办税服务厅在市委“含羞草”曝光活动中实现“零投诉”。红色教育学在前头。以支部为单位，分批组织全市国税系统324名党员干部走进永新、瑞金、井冈山等革命圣地开展“三个对话”红色精品访谈活动；组织65名科级党员干部走进革命圣地延安开展“弘扬延安精神、争做合格党员”党性教育，在全市国税系统开展了“今天是我的政治生日”、“党员回归社区志愿服务”“不忘初心牢记使命”重温入党誓词等活动，进一步厚植了党员干部红色基因，增强了党员与党组织的粘合度。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>（江西省新余市国家税务局 傅春光 陈玲锋）</strong></span></p><p><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '江西新余国税局：党旗引领启新程 不忘初心铸税魂', null, null, null, null, '20180323154622', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '2', '1', '1', '1', '1', null, '20180323154622', null, '20180323173814', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('224', '赤胆忠心为革命 侠骨柔情英雄心——读夏明翰给妻子的遗书', null, '<p class="sou1" style="margin: 20px auto 0px; padding: 0px; text-align: center; width: 639.612px; font-family: 宋体; font-size: 12px; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>王越</strong></span></p><p class="sou" style="margin: 10px auto 0px; padding: 0px; width: 639.612px; text-align: center; font-family: 宋体; font-size: 12px; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>2016年12月28日08:46&nbsp;&nbsp;&nbsp;&nbsp;来源：</strong></span><a href="http://cpc.people.com.cn/" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>人民网-中国共产党新闻网</strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 0em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; text-align: center;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><img alt="" src="/ueditor/jsp/upload/image/20180323/1521790758098046390.jpg"/></strong></span></p><p class="desc" style="margin: 10px auto; padding: 0px; text-indent: 0em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; text-align: center;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>夏明翰与妻子郑家均</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 0em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); font-size: 16px; font-family: 楷体;">亲爱的夫人钧：</span></strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); font-size: 16px; font-family: 楷体;">同志们常说世上唯有家钧好，今日里我才觉得你是巾帼贤。我一生无愁无泪无私念，你切莫悲悲戚戚泪涟涟。张眼望，这人世，几家夫妻偕老有百年。抛头颅，洒热血，明翰早已视等闲。“各取所需”终有日，革命事业代代传。红珠留作相思念，赤云孤苦望成全。坚持革命继吾志，誓将真理传人寰！</span></strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1928年3月18日，由于叛徒出卖，夏明翰在武汉被捕。在阴暗潮湿的监狱里，他用敌人给他写自首书的半截铅笔给妻子郑家钧写了这封催人泪下的家书，这也是夏明翰的遗书。写完后，年仅28岁的他抑制不住对妻子、对女儿的强烈爱恋和思念，用嘴唇和着鲜血，在遗书上亲吻下一个深深的吻印。这生离死别前的一个血吻，彰显出了夏明翰作为一个伟大的革命者的侠骨柔情、深情厚意和忠贞不渝的革命爱情。两天后，夏明翰在武汉市鹦鹉洲被国民党反动派枪决。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“世上唯有家钧好”</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“同志们常说世上唯有家钧好，今日里我才觉得你是巾帼贤。”家书的开头，夏明翰毫不掩饰地称赞了自己的妻子。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1920年秋，夏明翰来到长沙，面见仰慕已久的毛泽东。第二年冬，他经毛泽东、何叔衡介绍加入中国共产党，在长沙从事工人运动。他领导人力车工人罢工，迫使长沙县知事宣布削减车租。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>也就是在这时，湘绣女工郑家钧在掩护领导罢工斗争的夏明翰时，右臂中弹受伤，夏明翰经常来看望她，两人在接触过程中畅谈理想，交流革命体会，互生爱慕之情。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>爱的时光飞快逝去，几年的相恋使这对革命情侣感情日深。1926年4月的一天，毛泽东来到夏明翰房间，见他在洗衣服，颇有感触地说:“明翰，该找个伴侣啦！郑家钧对你不是很好吗？”</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>夏明翰回答:“家钧好！家钧好！”毛泽东高兴地说:“你们俩情投意合，志同道合，早点成家吧！”</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>经毛泽东挑明，1926年农历九月初四，郑家钧和夏明翰在一间简陋的民房里举行了婚礼,洞房就在长沙市清水塘四号。当时，婚礼虽然简朴，但却高朋满座，何叔衡、李维汉、谢觉哉、郭亮、易礼容、龚饮冰等都前来参加了婚礼。他们还向这对新人送了礼物，何叔衡送的是一个墨盒和一个钢笔架，李维汉送的是一对精巧的小壶，易礼容送的是一个上面剪贴着大红喜字的金鱼缸。同时，李维汉、何叔衡、谢觉哉等还给他们送了一对婚庆对联：“世间唯有家均好，天下谁比明翰强。”</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1927年春节前夕，两人搬到长沙市望麓园一号，与毛泽东、杨开慧同住一个院子。从那个春节开始，夏明翰跟郑家钧约定：工作之余，不走亲，不访友，一心一意帮郑家钧补习文化。从阿拉伯数字到常见汉字，从作诗填词到马列主义，夏明翰在家里教妻子学文化，也像在湘江中学、工农夜校上课一样认真，充分地备课，详细地解释，一遍又一遍地不厌其烦。据郑家钧回忆：“光是讲‘一’字，就讲了一个晚上。”在夏明翰尽心地言传身教下，郑家钧迅速成长。后来，大革命失败，在白色恐怖的逆境里，她陪伴夏明翰坐机关、送机密、会同志，甚至扮作名门之女、高贵太太，巧与敌人周旋，并最终制服对手，成为夏明翰的得力助手。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>一天晚上，夏明翰一进家门，便高兴地对妻子说：“家钧，我给你买了一样好东西。”看到丈夫安全地回家了，郑家钧心里非常高兴，又听说还给她买了好东西，更是高兴不已，她迎上去问道：“什么好东西啊？”夏明翰神秘地逗着她说：“你猜猜看啊！”郑家钧猜了半天也没猜出来。见她着急的样子，夏明翰便笑着打开了手里的纸包，原来是一颗闪闪发光的红珠子。郑家钧虽然很高兴，但却不明白为何送她这个，便笑着问买这个东西干什么？夏明翰风趣地说：“给你镶个戒指，让你戴在手指上，满意吗？我还在纸上写了两句诗呢！”</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>郑家钧听了，忙把包红珠子的纸展开，发现上面真的写着：“我赠红珠如赠心，但愿君心似我心！</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“看完这两句诗，郑家钧恍然大悟，一下子理解了丈夫为何送给她这颗红珠的心意。她明白丈夫是希望她永远怀着一颗红心，忠于人民，忠于党，忠于共产主义事业，在严峻的考验面前，永不变心。她既高兴又激动，慎重地把红珠包好，用坚定而又无限深情的眼光注视着丈夫，许久没有说话。夏明翰牺牲后，这颗红珠便成了她纪念丈夫唯一的珍贵遗物。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“坚持革命继吾志”</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>革命同志、人生伴侣，从相识、相知、相爱到喜结连理，如今却要阴阳两隔，怎能让人不痛心？！信中，夏明翰强忍着悲痛，劝慰妻子：“切莫悲悲戚戚泪涟涟。张眼望，这人世，几家夫妻偕老有百年。”与此同时，夏明翰在家书中表现出他坚定的革命意志和视死如归的精神境界：“抛头颅，洒热血，明翰早已视等闲。”面对敌人的酷刑，夏明翰宁死不屈。1928年3月20日清晨，当执行官问夏明翰还有什么话要说时，他大声说：“有，给我拿纸笔来！”于是，夏明翰写下了一首大义凛然的就义诗：“砍头不要紧，只要主义真。杀了夏明翰，还有后来人！”夏明翰饮弹倒下时，口中还念着他的就义诗。诗如其人，一字千金，字字是血，笔笔是心！这诗是他的性格，也是他的崇高信念！时隔数日，在得知丈夫遇难后，郑家钧怀着极度的悲痛，写了一首祭夫诗：“赤胆红心交给党，毕生精力献人民。昂首刑场洒热血，忠魂犹绕汉阳城。吊祭来迟悲更深，鹦鹉洲前日色红。不存白骨精神在，革命还有后来人。”</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>夏明翰英勇就义后，郑家钧谨遵丈夫遗言：“赤云孤苦望成全”，“坚持革命继吾志，誓将真理传人寰”。她一方面坚持从事革命活动，同时又含辛茹苦地把女儿抚育成人。1930年，郑家钧从长沙远赴上海，给一大户人家当佣工，因为有一手湘绣的绝活，受到雇主的欢迎。其实，郑家钧在当佣工的同时，还是一名地下交通员，主要是为上海的地下党收藏和保管文件，然后在指定的地点交给所指定的人，一切工作都是单线联系。她以惊人的勇气和胆识继承着丈夫的事业。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>夏明翰夫妇为女儿取名夏赤云，意为红色的云彩，寄托了夏明翰“子子孙孙，一代接一代，永远赤化下去”的愿望。为避免被国民党反动派斩草除根，夏明翰牺牲后，郑家钧将女儿的名字改为郑忆芸（后又改为夏芸），跟随外祖母一起在乡下长大。据夏芸回忆：“从我记事开始，就经常跟着外祖母、母亲躲难，母亲推着一辆三轮车，也没有什么行李物品，也是这家住10日，那家借住半月，日子苦得很。”“记忆里，母亲总是不分白天黑夜地纺纱织布，维持家用。”抗战期间，无论是长沙市里的小吴门、高桥，还是长沙周边的东乡、望城，甚至郴州、耒阳等地，郑家钧和女儿都因避难住过。郑家钧不分白天黑夜地绣花缝衣换取微薄收入以维持生计。抗战胜利后，夏芸回到长沙，并考入湖南私立周南女子中学。对于夏芸来说，“那时起才吃过饱饭”。1949年，夏芸考入武汉大学，仅仅读了半年书，因为交不起学费，不得不转入北京农业大学。此时的郑家钧随着年岁的增长，眼睛渐渐看不清细小的东西做不了刺绣，常年以糊纸盒为生，她清贫、低调，从未向组织提过任何要求。夏明翰生前的战友李维汉、谢觉哉等党和国家领导人每次到长沙，都要去看望郑家钧，亲切地称她为“老嫂子”。夏芸从北京农业大学毕业后，坚决服从组织安排，先后在江西的赣南、宜春、九江等地工作，始终践行“淡泊名利”的人生格言。她所从事的工作大都条件艰苦、环境恶劣，曾一年四季扎根深山，吃住在溶洞里，但鲜有人知道。作为夏明翰烈士的后人，退休后，夏芸深居简出，默默生活在九江市。“生活不能奢侈，我和我的子女们也没什么特殊的，他们都是靠自己的能力生活。”夏芸从小就教育子女要低调行事，不要因“烈士后代”感到与众不同，要凭自己的劳动去工作生活。她的所作所为无愧于“后来人”的身份！</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>夏明翰牺牲后，除了他的妻女，还有无数中华英雄儿女踏着烈士的足迹继续前进，终于迎来革命事业的胜利。解放后，郑家钧专程到汉阳凭吊丈夫，作七律一首：“闻君就义汉江城，慷慨高歌‘主义真’。气吞山河遗篇在，血溅沙洲浩气存。白骨推波卷巨浪，丹心永照‘后来人’。喜见今朝乾坤赤，英魂含笑看朝晖。”这是她对丈夫的怀念，也是她向丈夫唱出的胜利的凯歌！</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); font-size: 16px; text-indent: 2em; display: block;"><strong style="text-indent: 2em; color: rgb(0, 0, 128);">推荐阅读</strong></span></strong></span></p><hr/><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/xuexi/n1/2016/1111/c385474-28854779.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">习近平用“三个伟大”评价孙中山：倡导共筑中国梦</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1225/c369328-28974933.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">领略毛泽东诗词里的四大情怀</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1128/c85037-28901354.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">毛泽东何时称赞朱德“度量大如海”</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1129/c85037-28906908.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">纪念朱德诞辰130周年：追求真理，无限忠诚</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1212/c85037-28942416.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">汪建新：毛泽东的第一首军旅诗词</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1212/c85037-28941872.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">冒死营救秘密共产党人的军统女特工</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1223/c85037-28970981.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">1938年毛泽东与梁漱溟在延安的六次“交换意见”</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1122/c85037-28886777.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">刘华清将军与邓小平相识相交六十年</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1110/c85037-28849260.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">周恩来的政府管理智慧：谋定而后动</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1221/c85037-28964889.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">毛泽东在重庆谈判期间创作的一首七律政论诗</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1109/c85037-28846683.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">延安时期毛泽东解析名姓趣闻</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1114/c85037-28857713.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">王文王凤岐夫妇：电视剧《潜伏》主角原型</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1114/c85037-28859007.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">新中国成立后毛泽东诗词中的境界和情怀</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1116/c85037-28871025.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">重庆谈判期间毛泽东三顾特园访张澜</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://dangshi.people.com.cn/n1/2016/1114/c85037-28859073.html" target="_blank" style="text-decoration: underline; text-indent: 2em; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">哪位开国少将去世后如愿“回黑山陪战友”</span></strong></span></a></p><p><br/></p>', '赤胆忠心为革命 侠骨柔情英雄心——读夏明翰给妻子的遗书', null, null, null, null, '20180323153936', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '0', '1', '1', '1', '1', null, '20180323153936', null, null, '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('170', '【每周一星】袁思宇：以适航夯实质量“地基”', null, '<p><span style="color: rgb(0, 0, 0);"><strong>时间：2018年03月15日 09:29&nbsp;&nbsp;&nbsp;来源：大飞机报</strong></span></p><p><span style="color: rgb(0, 0, 0);"><strong><em style="display: inline-block; width: 27px; height: 20px; float: left; background-image: url(&quot;http://www.comac.cc/images/tags.png&quot;); background-position: 0px -30px; background-size: initial; background-repeat: no-repeat; background-attachment: initial; background-origin: initial; background-clip: initial;"></em><span style="color: rgb(0, 0, 0); float: left;">视力保护色：</span></strong></span></p><ul style="list-style-type: none;" class=" list-paddingleft-2"><li><p><br/></p></li><li><p><br/></p></li></ul><p><span style="color: rgb(0, 0, 0);"><strong>【字号&nbsp;</strong></span><a target="_self" style="color: rgb(0, 0, 0); text-decoration: underline;"><span style="color: rgb(0, 0, 0);"><strong>大</strong></span></a><span style="color: rgb(0, 0, 0);"><strong>&nbsp;</strong></span><a target="_self" style="color: rgb(0, 0, 0); text-decoration: underline;"><span style="color: rgb(0, 0, 0);"><strong>中</strong></span></a><span style="color: rgb(0, 0, 0);"><strong>&nbsp;</strong></span><a target="_self" style="color: rgb(0, 0, 0); text-decoration: underline;"><span style="color: rgb(0, 0, 0);"><strong>小</strong></span></a><span style="color: rgb(0, 0, 0);"><strong>】</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong><img src="/ueditor/jsp/upload/image/20180323/1521785861720073321.jpg"/></strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>&nbsp;</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　2015年7月，袁思宇进入上飞公司适航管理部担任适航检查室适航管理员，负责新支线飞机成品件、结构件适航检查和管理工作。两年来参与了ARJ21飞机106-107架机等多架次飞机的适航取证工作，现负责ARJ21飞机111架机和公务机适航协调工作。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　经常有人产生疑问，适航与质量有什么关系？适航与质量那么相似，是不是重复了？“适航应该是质量的‘地基 ’，是构建质量高楼大厦最坚实的基础。” 袁思宇这样解释道。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　2015年7月，袁思宇通过校园招聘进入上飞公司，2年多的时间，他从一开始的懵懂到在适航管理方面独当一面，都与自身的努力分不开。“办法总比困难多，我也相信‘伸手不打笑脸人’，工作上认真求知的态度总会让别人理解并给予帮助和指导。”</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　一次，在负责预投产阶段的成品件挂签工作时，局方对于P项挂签提交的材料要求异常严格。虽然相关的适航要求早已沟通供应商，但袁思宇仍然发现挂签文件存在问题。他用半个月时间在现场办公，与同事沟通供应商应提交的材料要求、局方检查材料时提出问题的答复方式以及相关流程细节。经过多次面对面的交流，供应商提交的文件材料质量有明显的上升。“后来以此类推，我又通过这种方式帮助质量管理部提高了P项检查声明提交质量。检查不再需要花费大量的精力，只需要跟踪状态和解决特殊问题。”袁思宇说。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　责任明确，流程清晰，对于工作职责范围内的事情，袁思宇要求自己前因后果清清楚楚，一切工作以程序为依据。用他的话来说，适航是质量的“地基”，“地基”动摇了，大楼不会稳。保证工作的可追溯性，让质量经得起历史的检验，他一直在努力。（王新燕 文/严天宇 摄）</strong></span></p><p class="printBtn" style="margin-top: 0px; margin-bottom: 0px; margin-left: 374px; padding: 0px; float: left; display: inline; width: 100px; line-height: 32px;"><a target="_self" style="font-family: 宋体; color: rgb(0, 0, 0); text-decoration: underline;"><span style="color: rgb(0, 0, 0);"><strong><em style="width: 23px; height: 23px; display: block; margin-top: 5px; float: left; background-image: url(&quot;http://www.comac.cc/images/tags.png&quot;); background-position: 0px -75px; background-size: initial; background-repeat: no-repeat; background-attachment: initial; background-origin: initial; background-clip: initial;"></em>打印页面</strong></span></a></p><p><span style="color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); float: left;">分享到：</span></strong></span></p><p><span style="color: rgb(0, 0, 0);"><strong><span class="BSHARE_COUNT bshare-share-count" style="float: none; display: inline-block; width: 41px; background-image: url(&quot;//static.bshare.cn/frame/images/counter_box_18.gif&quot;); background-position: initial; background-size: initial; background-repeat: no-repeat; background-attachment: initial; background-origin: initial; background-clip: initial; height: 18px; color: rgb(51, 51, 51); text-align: center; font-weight: bold; font-stretch: normal; font-size: 11px; font-family: Arial, 宋体, sans-serif; zoom: 1; line-height: 18px !important;">0</span></strong></span></p><h1 style="margin: 0px; padding: 0px 0px 0px 15px; height: 26px; width: 95px; background-color: rgb(0, 78, 162); color: white; font-size: 14px; line-height: 26px; float: left;"><span style="color: rgb(0, 0, 0);"><strong>相关报道:</strong></span></h1><p><span style="color: rgb(0, 0, 0);"><strong><em style="width: 35px; height: 26px; display: block; float: left; background: url(&quot;http://www.comac.cc/images/tags.png&quot;) 0px 0px no-repeat;"></em></strong></span></p><ul style="list-style-type: none;" class=" list-paddingleft-2"><li><p><a href="http://www.comac.cc/gywm/qywh/rwfc/201802/24/t20180224_6197250.shtml" target="_blank" style="text-decoration: underline; font-size: 13px; color: rgb(0, 0, 0);"><span style="color: rgb(0, 0, 0);"><strong>【每周一星】上飞公司马周： 质量工作上的“秀才”</strong></span></a><span style="color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); position: absolute; top: 5px; right: 0px; float: right;">2018年02月24日</span></strong></span></p></li><li><p><a href="http://www.comac.cc/gywm/qywh/rwfc/201802/06/t20180206_6149848.shtml" target="_blank" style="text-decoration: underline; font-size: 13px; color: rgb(0, 0, 0);"><span style="color: rgb(0, 0, 0);"><strong>【总师风采】C919大型客机副总设计师王伟：干试飞，压力和喜悦都特别大</strong></span></a><span style="color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); position: absolute; top: 5px; right: 0px; float: right;">2018年02月06日</span></strong></span></p></li><li><p><a href="http://www.comac.cc/gywm/qywh/rwfc/201802/01/t20180201_6133972.shtml" target="_blank" style="text-decoration: underline; font-size: 13px; color: rgb(0, 0, 0);"><span style="color: rgb(0, 0, 0);"><strong>【每周一星】黄尚伟：一个电话随叫随到</strong></span></a><span style="color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); position: absolute; top: 5px; right: 0px; float: right;">2018年02月01日</span></strong></span></p></li><li><p><a href="http://www.comac.cc/gywm/qywh/rwfc/201801/31/t20180131_6129682.shtml" target="_blank" style="text-decoration: underline; font-size: 13px; color: rgb(0, 0, 0);"><span style="color: rgb(0, 0, 0);"><strong>C919首飞机组成员张大伟：用青春搏击长空</strong></span></a><span style="color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); position: absolute; top: 5px; right: 0px; float: right;">2018年01月31日</span></strong></span></p></li><li><p><a href="http://www.comac.cc/gywm/qywh/rwfc/201801/02/t20180102_6027131.shtml" target="_blank" style="text-decoration: underline; font-size: 13px; color: rgb(0, 0, 0);"><span style="color: rgb(0, 0, 0);"><strong>汪士才：摸索书法的“门道”</strong></span></a><span style="color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); position: absolute; top: 5px; right: 0px; float: right;">2018年01月02日</span></strong></span></p></li></ul><p><br/></p>', '【每周一星】袁思宇：以适航夯实质量“地基”
