INSERT INTO "public"."information" VALUES ('174', '生态环境部组建 李干杰任部长、党组书记', null, '<p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>中国共产党新闻网北京3月23日电 &nbsp; (记者姚茜)据生态环境部微信公号消息，3月22日下午，生态环境部召开干部大会，中央组织部有关同志宣布了中央关于组建生态环境部和领导班子任命的决定，李干杰同志任生态环境部部长、党组书记。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>李干杰同志简历</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; text-align: center;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><img src="http://scgh.gobestsoft.com:18080/ueditor/jsp/upload/image/20180323/1521786345311005671.jpg"/></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>李干杰，男，汉族，1964年11月出生，湖南望城人，1984年加入中国共产党，研究生学历，工学硕士，高级工程师。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1981年9月在清华大学核反应堆工程专业学习，1986年7月在清华大学攻读核反应堆工程与安全专业硕士研究生。1989年7月研究生毕业后在国家核安全局北京核安全中心参加工作，历任国家环境保护总局核安全与辐射环境管理司副司长，国家环境保护总局核安全中心主任、党委副书记（正局级），国家环境保护总局核安全司司长等职务。2006年12月任国家环境保护总局副局长、党组成员、国家核安全局局长。2008年3月任环境保护部副部长、党组成员、国家核安全局局长。2016年10月任河北省委副书记，省委党校校长。2017年5月任环境保护部党组书记，2017年6月任环境保护部部长。2018年3月任生态环境部部长、党组书记。</strong></span></p><p><br/></p>', '生态环境部组建 李干杰任部长、党组书记', null, null, null, null, '20180323142603', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '1', '0', '14', '1', '1', '1', '1', null, '20180323142603', null, '20180323171552', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('255', '关于印发《关于在上飞公司开展“一党员一承诺+一支部一品牌”主题活动的实施方案》的通知', null, '<p><span style="color: rgb(102, 102, 102); font-family: Arial, Helvetica, simsun, sans-serif; font-size: 14px; text-align: center; background-color: rgba(242, 242, 242, 0.976);">关于印发《关于在上飞公司开展“一党员一承诺+一支部一品牌”主题活动的实施方案》的通知</span></p>', '关于印发《关于在上飞公司开展“一党员一承诺+一支部一品牌”主题活动的实施方案》的通知', null, null, null, null, '20180326105846', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '0', '0', '0', '0', '0', '2', '1', '1', '1', '1', null, '20180326105846', null, null, '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('178', '习近平应约同法国总统马克龙通电话', null, '<p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>22日，国家主席习近平应约同法国总统马克龙通电话。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　马克龙祝贺习近平当选连任中国国家主席。马克龙表示，我珍视法中友谊，高度关注中国全国“两会”取得的各项成果，愿继续同习主席共同努力，落实好我们就深化法中关系达成的重要共识。法中双方要密切高层交往，深化经贸、投资、农业、核能、环境等领域合作，加强在应对气候变化、维护多边贸易体制、防范金融风险等全球性问题上沟通协调。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　习近平指出，总统先生在中国全国“两会”闭幕不久即来电祝贺，体现出你对中国发展的关注和对中法关系的高度重视。今年是中国改革开放40周年。刚刚结束的中国全国“两会”对中国未来发展具有重要意义。今后一个时期，将是中国继续深化改革、扩大开放、实现更大发展的时期，也将是中国为世界作出更大贡献的时期。我相信，中国的发展将为中法、中欧合作提供更多机遇。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　习近平强调，不久前，总统先生首次访华时，我们就加强两国各领域合作达成重要共识，为中法关系注入了新的动力。中方愿同法方一道，密切高层交往，办好机制性对话，落实好合作共识，及时就重大问题进行沟通，把中法全面战略伙伴关系打造得更加富有生机。中法都是联合国安理会常任理事国和具有全球影响的大国。在当前复杂多变的国际形势下，中方愿同法方携手努力，加强战略沟通协调，共同致力于维护并完善现行国际秩序和全球治理体系，坚持多边主义，促进世界多极化、经济全球化，共同打造开放的全球贸易体系。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　两国元首还就共同关心的国际和地区热点问题交换了看法。(新华社北京3月22日电)</strong></span></p><p style="white-space: normal;"><br/></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　《 人民日报 》（ 2018年03月23日 01 版）</strong></span></p><p><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '习近平应约同法国总统马克龙通电话', null, null, null, null, '20180323143008', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '0', '1', '1', '1', '1', null, '20180323143007', null, '20180323171857', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('234', '在一线：为学生党员成长精准导航', null, '<p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“我也快拥有一个‘小红本’啦！”河北科技大学环工学院141班的李雅楠同学曾在日记中如此表达内心深处的殷殷期待。2015年12月13日，她认真地记下这一刻：我有幸通过了党组织的考验、成为一名中共预备党员，接过学院给每一名党员准备的“小红本”，心中欣喜的同时更充满了一份沉甸甸的责任。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这个在学生心目中有着磁铁般魔力的“小红本”究竟是什么呢？&nbsp;</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　河北科大环工学院党委副书记刘万里介绍，2015年，为贯彻落实好中组部、中宣部和教育部联合发出的《关于进一步加强高校学生党员发展和教育管理服务工作的若干意见》以及中共教育部党组发出的关于做好“两学一做”学习教育工作的通知精神，学院推出了“党员成长工程”，即自学生入党之日起，为每一位学生党员发一本红色的《学生党员成长记录册》（学生爱称“小红本”），每个月内，学生党员要及时将理论学习、工作感悟、组织生活、作风纪律、发挥先锋模范作用等方面的点滴表现记录在册。每月底前，学院党组织定期收上来逐个批阅，针对学生记录内容进行一对一点评指导，直至学生毕业结束。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　记者在调研中了解到，河北科大环工学院通过“党员成长工程”中的“小红本”载体，拉近了学生党员与党组织的距离，加强了学生与老师之间的交流沟通，实现了对每一位学生党员精准化培养的教育指导，有效调动了广大积极分子尽快加入党组织的决心和行动。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　与学生的进一步座谈中，给排水专业131班郭芳谈到对“小红本”的内心感受时说，“‘小红本’像写日记一样记录自己的点滴成长、点滴心得，这不仅仅是一个支部监督党员成长或者说自己和支部双方交流的平台，更是一本意义重大的回忆册，它有关‘大学’、有关‘青春’、有关‘梦想’、有关‘成长’，让我回忆满满，感动满满。”</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　环工学院142班席艺慧谈到“小红本”时感慨地说，“通过‘小红本’，我慢慢感觉到和学院党委书记离得越来越近，书记不再是那种‘不食人间烟火’的领导者，而是一个老朋友，用你自己能接受的方式和角度和你交流，也会特别耐心地为纠正你一个错误的观念给你写满一页的佐证材料。我都感觉离不开这个‘小红本’了。”</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　来自环工学院L131班的马飞飞，在自己的“小红本”上曾经庄重记录下自己的梦想：我立志要参加西部计划西藏专项志愿者，到西部去，到基层去，到人民最需要的地方去放飞自己人生的梦想！在学院党组织的指导和推荐下，怀揣着对祖国西部这片热土的热爱和志愿者的激情，她如愿奔赴西藏拉萨。当地同事评价马飞飞性格开朗、为人和善，工作认真负责、不怕苦累，处处彰显了一名新时期西部志愿者的优秀品格。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“通过‘小红本’这个载体的积累，我的政治理论知识更为丰富，政治理论修养也有了极大的提高，对党的方针政策认识不断加深。认真进行‘两学一做’的学习，向着一名合格的党员而不懈努力。‘小红本’是我向上的力量。我相信只要付出艰苦的努力，梦想终究会实现。我会不忘初心，继续前进！”这是今年同时被江苏省公务员考试和河北省委组织部选调生录用的大四学生党员朱岩岩谈到“小红本”时发自内心的感慨。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　安全工程专业L121班王森深有感触地说：“成长记录册记录了我们从成为预备党员开始每一时期、每一阶段各方面的变化。在记录的过程中必须勤于思考、善于观察、善于总结，必须对自己有正确的认识，形成批评与自我批评的好习惯。作为一名预备党员，作为学生的榜样，无论在生活还是学习过程中积极传播正能量是我们的责任也是义务。”</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　河北科技大学党委书记王余丁表示，将进一步改进、规范并推广环工学院党员成长记录册的内容和形式，努力增强全体学生党员的党性修养，引导大学生用中国梦激扬青春梦，让青春梦与中国梦和谐共振，实现让一批批合格的学生党员带动所有学生共同进步和提升的目的。（董洪亮 任文海）</strong></span></p><p style="white-space: normal;"><br/></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　《 人民日报 》（ 2018年03月22日 18 版）</strong></span></p><p style="white-space: normal;"><br/></p><p><br/></p>', '在一线：为学生党员成长精准导航', null, null, null, null, '20180323155244', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '0', '1', '1', '1', '1', null, '20180323155244', null, '20180323174117', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('211', '宋涛会见美国前总统国家安全事务助理哈德利', null, '<p class="sou" style="margin: 10px auto 0px; padding: 0px; width: 639.611px; text-align: center; font-family: 宋体; font-size: 12px; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>2018年02月27日07:17&nbsp;&nbsp;&nbsp;&nbsp;来源：</strong></span><a href="http://paper.people.com.cn/rmrb/html/2018-02/27/nw.D110000renmrb_20180227_6-03.htm" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>人民网－人民日报</strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>中共中央对外联络部部长宋涛26日在北京会见了美国前总统国家安全事务助理、和平研究所董事会主席哈德利。（新华社北京2月26日电）</strong></span></p><p><br/></p>', '宋涛会见美国前总统国家安全事务助理哈德利', null, null, null, null, '20180323152413', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '0', '1', '1', '1', '1', null, '20180323152412', null, null, '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('241', '执政能力建设：新时代党建着力点', null, '<p style="white-space: normal;"><span style="color: rgb(0, 0, 0);"><strong>原标题：执政能力建设：新时代党建着力点</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党的十九大报告关于提高党的执政能力和领导水平的论断，无论在思想创新还是实践创新上，都实现了新飞跃。特别是，强调“加强党的长期执政能力建设”“不断增强党的政治领导力、思想引领力、群众组织力、社会号召力”以及要求增强学习本领、政治领导本领、改革创新本领、科学发展本领、依法执政本领、群众工作本领、狠抓落实本领、驾驭风险本领等，为全面增强执政本领谋划新篇、开辟新路，标志着新时代党的执政能力建设理论和实践实现了新飞跃。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　实现标准、目标和层次的跨越</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　中国共产党是具有远大抱负和崇高追求的使命型政党。从明确提出党的执政能力建设课题以来，我们党围绕长期执政、科学执政、民主执政和依法执政，不断创新发展执政能力建设理论。党的十九大报告在“执政能力”前面加上“长期”二字，刷新了新时代的壮志雄心、理性自信和崇高精神。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　第一，刷新壮志雄心。“目标很伟大、支撑有薄弱”，是制约长期执政目标实现的一大障碍和瓶颈。从执政到长期执政，不仅是传统意义的进程跨越，而且还是具有丰富内涵的标准跨越、目标跨越、层次跨越。它全面刷新了新时代中国共产党人追求崇高使命、追求远大抱负、追求伟大理想的高度、格局和境界。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　第二，刷新理性自信。党的十八大以来发生的历史性变革证明，中国共产党拥有广泛的认同和无可比拟的先进性。同时，中国共产党通过波澜壮阔的伟大实践，执政能力经受了锤炼和洗礼，具备了更加坚实的能力基础以及向更高层次迈进的客观条件。党的十九大不失时机地提出加强长期执政能力建设，标志着我们党更加理性、更加成熟、更加自信，也更有后劲、更有实力、更有前景。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　第三，刷新崇高精神。党的先进性最本质的体现是党的崇高性，不仅体现在使命的崇高上，而且体现在精神的崇高上。党的崇高精神，就是勇于变革、勇于创新、勇于突破、勇于发展的精神，就是不懈追求、不懈向往、不懈前进、不懈奋斗的精神，就是坚持自我净化、自我完善、自我革新、自我提高的精神。执政能力建设前面加上“长期”二字，既刷新了共产党人永不满足、永不懈怠、永不僵化、永不停步的精神内核和豪迈气概，又刷新了一个成熟政党依然胸怀强烈的忧患意识并坚持寻找不足、发现问题、弥补短板的清醒自觉和伟大担当。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　创新建设思路　深化规律探索</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党的执政能力建设理论创新，一直在探索中发展、在发展中完善。党的十八大以来，我们党通过创新执政能力建设思路、构建增强执政本领体系，实现了执政能力建设理论的突破。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一是把握执政规律进入新层次。从党的十六大提出提高科学判断形势能力、驾驭市场经济能力、应对复杂局面能力、依法执政能力和总揽全局能力“五大能力”，发展到党的十九大提出不断增强党的政治领导力、思想引领力、群众组织力、社会号召力“四力标准”，无论是在概括表达还是内涵本质层面都实现了新突破、新跨越、新发展。它不仅直击执政党领导人民改革发展的关键本质和要害问题，而且有利于执政党的自我塑造和自我提升。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　二是扎根时代沃土达至新高度。习近平新时代中国特色社会主义思想确立为党必须长期坚持的指导思想和行动指南，确保了最鲜活的马克思主义理论创新成果在中国大地落地生根。这一新的指导思想给党的执政能力建设提出了更高要求。“四力标准”就是落实理论武装、践行时代要求的具体体现：提高政治领导力，突出了党领导一切的原则；提高思想引领力，突出了物质和精神协同进步的要求；提高群众组织力，突出了以人民为中心的思想和人民当家作主的理念；提高社会号召力，突出了国家治理体系和治理能力现代化。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　三是发展执政理论迈向新阶段。纵观我们党执政能力建设理论发展的过程，大致经历了理念探索、实践探索、规律探索三个阶段。以党的十九大正式提出长期执政能力建设和“四力标准”“八项本领”为主要标志，我们党在执政能力建设理论发展上来到了规律探索的全新阶段。这个阶段，层次更高、突破更大，规律性更强、真理性更强。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“四力标准”牵引“八项本领”支撑</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党的十九大提出的执政能力建设新概念、新目标、新任务、新要求，为新时代增强执政本领打开了一扇创新之门。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　赋予崭新的科学体系。其主要标志有：创造性地构建以加强长期执政能力建设为统领，以增强政治领导力、思想引领力、群众组织力、社会号召力为中枢，以增强学习本领、政治领导本领、改革创新本领、科学发展本领、依法执政本领、群众工作本领、狠抓落实本领、驾驭风险本领为支撑的科学体系。从顶层设计、逻辑支撑、实践推进上，赋予了更加明确的方向、更加清晰的路线图、更加现实的强支撑。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　赋予崭新的逻辑支撑。“四力标准”属于躯干性能力、框架性能力，具有引领方向的核心功能；“八项本领”属于支撑性能力、延展性能力，具有确保建设目标落地落实的核心功能。有了“四力标准”的牵引与“八项本领”的支撑，党的长期执政能力建设必将取得更大的成绩。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　赋予崭新的根本抓手。“四力标准”再先进、再科学，如果没有执政骨干队伍的整体能力支撑，都将是风雨飘摇的脆弱柱梁。从这个意义上说，只要全党上下特别是党的各级领导干部不断增强“八项本领”，不断重塑、不断发展、不断跃升，长期执政的目标就不会落空。中华民族伟大复兴的中国梦就一定能够在共产党人的接力奋斗中成为现实。（周新民 中国石化集团公司）</strong></span></p><p><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '执政能力建设：新时代党建着力点', null, null, null, null, '20180323161049', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '22', '1', '1', '1', '1', null, '20180323161049', null, '20180323173335', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('244', '中宣部召开“新时代新气象新作为”主题采访活动专题座谈会', null, '<p style="white-space: normal;"><span style="color: rgb(0, 0, 0);"><strong>原标题：推动新思想深入人心　呈现新时代万千气象——中宣部召开“新时代新气象新作为”主题采访活动专题座谈会</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>中宣部１５日在陕西延安召开“新时代新气象新作为”主题采访活动专题座谈会，总结交流此次主题采访活动前一阶段报道情况，对下一阶段工作进行安排部署。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>中宣部副部长、国务院新闻办公室主任蒋建国在座谈会上表示，开展“新时代新气象新作为”主题采访活动以来，中央和各地主要媒体紧紧围绕习近平新时代中国特色社会主义思想和党的十九大精神这条主线，持续推出了一批有思想有精神、有故事有温度的新闻报道，充分反映广大干部群众用党的创新理论武装头脑、指导实践、推动工作的生动局面。继续深入开展此次主题报道，要保持强烈的学习意识、坚守强烈的为民情怀、贯彻强烈的融合意识、树立强烈的受众意识、确立强烈的统筹意识，推动学习宣传贯彻习近平新时代中国特色社会主义思想和党的十九大精神不断往深里走、往实里走、往心里走。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“新时代新气象新作为”主题采访活动于２０１７年１１月底在上海中共一大会址纪念馆启动。从上海石库门到延安杨家岭，从党的一大到七大，各媒体选派的记者沿着中国共产党的成长“坐标”，在信仰与思想的精神洗礼中，坚定理想信念，肩负使命担当。一个多月来，记者们深入社区工厂、街头巷尾、田间地头、祖国边陲采访，一些媒体的负责人带队采访，撰写署名报道。目前，主题采访活动有声有色、有质有量，大多数中央和地方媒体每天在头版首页首屏等重要位置刊发报道。据不完全统计，各媒体已推出各类原创稿件超过４５００篇，此次主题采访相关报道引发网友持续关注和热议。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>中宣部、中央网信办、国家新闻出版广电总局、中国记协、各省区市宣传部有关负责同志，３０家中央和地方媒体的负责同志及骨干编辑记者，专家学者等约１５０人出席座谈会。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>与会人士认为，“新时代新气象新作为”主题采访活动开展以来，各媒体坚持移动优先，充分应用新技术新手段，制作推出有影响、有特色的融媒体产品，提升了新闻报道的吸引力感染力影响力。广大编辑记者充分发扬“走转改”精神，在讲故事、挖细节上花心思，在时、度、效上下功夫，倾情呈现新时代的万千气象，令人感受到党的十九大以来阵阵新风扑面，感受到干部群众创造美好生活的热情干劲，也对外传递出中国的新时代气息和新民生温度。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>座谈会后，与会人士瞻仰了党的七大会址和延安新闻纪念馆。相关媒体的编辑记者还将在延安革命老区深入开展集中采访。（新华社西安１月１５日电 记者黄小希、姜辰蓉）</strong></span></p><p><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '中宣部召开“新时代新气象新作为”主题采访活动专题座谈会', null, null, null, null, '20180323161356', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '2', '1', '1', '1', '1', null, '20180323161356', null, '20180323173245', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('200', '关于做好2017年度《企业年度工作报告》编报工作的通知', null, '<p><span style="color: rgb(0, 0, 0);"><strong>时间：2017年11月30日 13:25&nbsp;&nbsp;&nbsp;来源：国务院国资委网站</strong></span></p><p><span style="color: rgb(0, 0, 0);"><strong><em style="display: inline-block; width: 27px; height: 20px; float: left; background: url(&quot;http://www.comac.cc/images/tags.png&quot;) 0px -30px no-repeat;"></em><span style="color: rgb(0, 0, 0); float: left;">视力保护色：</span></strong></span></p><ul style="list-style-type: none;" class=" list-paddingleft-2"><li><p><br/></p></li><li><p><br/></p></li></ul><p><span style="color: rgb(0, 0, 0);"><strong>【字号&nbsp;</strong></span><a target="_self" style="color: rgb(0, 0, 0); text-decoration: underline;"><span style="color: rgb(0, 0, 0);"><strong>大</strong></span></a><span style="color: rgb(0, 0, 0);"><strong>&nbsp;</strong></span><a target="_self" style="color: rgb(0, 0, 0); text-decoration: underline;"><span style="color: rgb(0, 0, 0);"><strong>中</strong></span></a><span style="color: rgb(0, 0, 0);"><strong>&nbsp;</strong></span><a target="_self" style="color: rgb(0, 0, 0); text-decoration: underline;"><span style="color: rgb(0, 0, 0);"><strong>小</strong></span></a><span style="color: rgb(0, 0, 0);"><strong>】</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　<strong style="line-height: 28px;">国务院国有资产监督管理委员会文件</strong>&nbsp;</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　<strong style="line-height: 28px;"><span style="color: rgb(0, 0, 0); font-family: Arial;">国资发监督一〔2017〕190号</span></strong>&nbsp;</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　<strong style="line-height: 28px;"><span style="color: rgb(0, 0, 0); font-family: Arial;">关于做好2017年度《企业年度工作报告》编报工作的通知</span></strong>&nbsp;</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>各中央企业：</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　依照《国有企业监事会暂行条例》（国务院令第<span style="color: rgb(0, 0, 0); line-height: 28px;">283</span>号）、《关于印发&lt;关于加强和改进国有企业监事会工作的若干意见&gt;的通知》（国资发监督〔<span style="color: rgb(0, 0, 0); line-height: 28px;">2006</span>〕<span style="color: rgb(0, 0, 0); line-height: 28px;">174</span>号）和《关于进一步支持配合监事会开展监督检查工作有关事项的通知》（国资发监督〔<span style="color: rgb(0, 0, 0); line-height: 28px;">2012</span>〕<span style="color: rgb(0, 0, 0); line-height: 28px;">120</span>号）的有关规定，各中央企业每年向监事会报送《企业年度工作报告》（以下简称年度报告）。为做好<span style="color: rgb(0, 0, 0); line-height: 28px;">2017</span>年度报告编报工作，现将有关事项通知如下：</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　一、加强组织协调，层层落实编报责任</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　年度报告编报工作涵盖范围广、涉及内容多、时间要求紧、质量要求高。各中央企业要进一步提高思想认识，全面总结以往年度的经验做法，建立健全编报工作管理体制和机制，压实工作责任，细化工作措施，落实工作任务。要加强组织领导，突出工作重点，强化成果运用，形成工作闭环。要早准备、早动员、早部署、早落实，层层分解目标任务，逐级落实责任分工，抓深抓细抓实。要选优配强各级编报人员，将编报责任具体落实到人，综合运用考核评价等奖惩手段调动广大编报人员的积极性、主动性和创造性，确保优质完成编报任务。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　二、梳理全年工作，充分揭示问题风险</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　年度报告编报工作是集中梳理排查全年工作，自我预警预判问题风险，助力监管、提升管理的重要载体。各中央企业要以年度报告编报工作为契机，全面梳理学习贯彻党的十九大精神，贯彻全国国有企业党建工作会议精神，深度推进企业党建各项具体工作完成情况。要逐项对照国家重大决策部署和国资监管重点任务要求，系统总结推进供给侧结构性改革，实施创新驱动发展战略，打好瘦身健体、提质增效攻坚战等各项重点工作落实情况。要结合监事会反映企业问题，认真梳理关键领域和重要环节存在的重大问题风险，形成自我监督与外部监督的良性互动机制。要推动解决带有普遍性、倾向性的重点问题，努力实现以整改促管理的工作成效。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　三、积极支持配合，规范核定编报范围</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　年度报告编报范围要适应企业产权关系、组织架构、管理模式的发展变化，根据监事会监督检查工作需要，在去年基础上认真核定今年的编报范围并调整确认。原则上，中央企业集团、境内（外）二级单位、各级金融子企业以及所托管企业纳入编报范围；整体上市中央企业控股上市公司所属境内（外）二级单位纳入编报范围；离岸公司、壳公司等特殊子企业不纳入编报范围，监事会另有要求的除外。根据监事会年度监督检查计划，中央企业重要参股企业、境外单位、混合所有制企业、三级（含）以下重要子企业及重要非法人实体，纳入当年重点编报范围。当年新收购企业和处置出售企业可适当简化报送。继续鼓励有条件的中央企业试行全级次报送。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　四、试用编报软件，提升工作质量和效率</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　年度报告编报方法要适应国资监管体制和监管方式变化的要求，持续创新完善。为推动年度报告电子化编报，国资委借鉴试点企业的成功经验，组织开发了单机版编报软件，旨在解决编报组织工作不便捷、编报内容质量难控制、编报格式标准不规范、编报汇总审核工作量大等问题，要求中央企业集团总部全面试用年度报告编报软件，鼓励各级编报单位积极参与试用。因特殊情况确实不具备试用条件的企业，可在备案环节向国资委作出书面说明，继续沿用原有的软件报送。使用编报软件的企业要充分利用各种载体和平台加大培训组织力度，熟练掌握软件操作，为优质高效完成编报工作任务奠定坚实基础，并将典型经验和有关意见建议及时反馈国资委，共同探索利用信息技术手段提升编报质量和效率的有效途径。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　五、落实编报任务，按时规范备案报送</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　（一）请各中央企业于<span style="color: rgb(0, 0, 0); line-height: 28px;">2017</span>年<span style="color: rgb(0, 0, 0); line-height: 28px;">12</span>月<span style="color: rgb(0, 0, 0); line-height: 28px;">15</span>日前将与派驻本企业监事会共同确定的拟报送年度报告有关事项，以正式文件形式（式样见附件<span style="color: rgb(0, 0, 0); line-height: 28px;">1</span>）报监督一局备案（纸质材料<span style="color: rgb(0, 0, 0); line-height: 28px;">1</span>套，光盘<span style="color: rgb(0, 0, 0); line-height: 28px;">1</span>套）。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　（二）请各中央企业于<span style="color: rgb(0, 0, 0); line-height: 28px;">2018</span>年<span style="color: rgb(0, 0, 0); line-height: 28px;">2</span>月<span style="color: rgb(0, 0, 0); line-height: 28px;">28</span>日前将集团公司与各级子企业年度报告一并以正式文件形式（式样见附件<span style="color: rgb(0, 0, 0); line-height: 28px;">2</span>）报送派驻本企业监事会（纸质材料<span style="color: rgb(0, 0, 0); line-height: 28px;">1</span>套，光盘<span style="color: rgb(0, 0, 0); line-height: 28px;">2</span>套），同时将年度报告及正式文件（光盘各<span style="color: rgb(0, 0, 0); line-height: 28px;">1</span>套）报送监督一局备案。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　各中央企业在编报过程中遇到的问题，请及时与派驻本企业监事会或监督一局联系。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　联系人及电话：国资委监督一局<span style="color: rgb(0, 0, 0); line-height: 28px;">&nbsp;</span>崔竹、刘阳</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　<span style="color: rgb(0, 0, 0); line-height: 28px;">010</span>-<span style="color: rgb(0, 0, 0); line-height: 28px;">64471800</span>、<span style="color: rgb(0, 0, 0); line-height: 28px;">64471801</span>、<span style="color: rgb(0, 0, 0); line-height: 28px;">010</span>-<span style="color: rgb(0, 0, 0); line-height: 28px;">64471356</span>（传真）</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　地<span style="color: rgb(0, 0, 0); line-height: 28px;">　　</span>址：北京市安定门外大街<span style="color: rgb(0, 0, 0); line-height: 28px;">56</span>号</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　邮政编码：<span style="color: rgb(0, 0, 0); line-height: 28px;">100011</span>&nbsp;</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　附件：<span style="color: rgb(0, 0, 0); line-height: 28px;">1</span>.</strong></span><a href="http://cms.ce.cn/wcm/app/n2588030/c8275457/part/8275474.wps" style="text-decoration: underline; line-height: 28px; color: rgb(0, 0, 0);"><span style="color: rgb(0, 0, 0);"><strong>关于××××公司拟报送2017年度《企业年度工作报告》的报告（式样）</strong></span></a><span style="color: rgb(0, 0, 0);"><strong>&nbsp;</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>　　<span style="color: rgb(0, 0, 0); line-height: 28px;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;2</span>.</strong></span><a href="http://cms.ce.cn/wcm/app/n2588030/c8275457/part/8275475.wps" style="text-decoration: underline; line-height: 28px; color: rgb(0, 0, 0);"><span style="color: rgb(0, 0, 0);"><strong>关于××××公司2017年度《企业年度工作报告》的报告（式样）</strong></span></a><span style="color: rgb(0, 0, 0);"><strong>&nbsp;</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong>国<span style="color: rgb(0, 0, 0); line-height: 28px;">　</span>资<span style="color: rgb(0, 0, 0); line-height: 28px;">　</span>委</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 0px; line-height: 28px;"><span style="color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); line-height: 28px;">2017</span>年<span style="color: rgb(0, 0, 0); line-height: 28px;">11</span>月<span style="color: rgb(0, 0, 0); line-height: 28px;">16</span>日</strong></span></p><p><br/></p>', '关于做好2017年度《企业年度工作报告》编报工作的通知', null, null, null, null, '20180323151022', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '1', '0', '2', '1', '1', '1', '1', null, '20180323151022', null, null, '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('209', '习近平：如果破坏生态环境，即使是有需求的产能也要关停', null, '<p style="margin-top: 10px; margin-bottom: 10px; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; line-height: 30px; font-family: SimSun; color: rgb(38, 33, 74); text-align: center; background-color: rgb(248, 248, 248);"><a href="http://cpc.people.com.cn/xuexi/" target="_blank" style="text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><img alt="" src="http://scgh.gobestsoft.com:18080/ueditor/jsp/upload/image/20180323/1521789702422034676.jpg"/></strong></span></a></p><p style="margin-top: 10px; margin-bottom: 10px; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; line-height: 30px; font-family: SimSun; color: rgb(38, 33, 74); text-align: center; background-color: rgb(248, 248, 248);"><a href="http://cpc.people.com.cn/xuexi/" target="_blank" style="text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>“学习路上”大型网络数据库</strong></span></a><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>&nbsp;&nbsp;</strong></span><a href="http://cpc.people.com.cn/xuexi/" target="_blank" style="text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>点击进入</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); font-size: 16px; font-family: 楷体; text-indent: 2em; display: block;">【学习路上按】党的十八大以来，习近平同志关于社会主义生态文明建设的一系列重要论述，立意高远，内涵丰富，思想深刻，对于我们深刻认识生态文明建设的重大意义，坚持和贯彻新发展理念，正确处理好经济发展同生态环境保护的关系，坚定不移走生产发展、生活富裕、生态良好的文明发展道路，加快建设资源节约型、环境友好型社会，推动形成绿色发展方式和生活方式，推进美丽中国建设，实现中华民族永续发展，夺取全面建成小康社会决胜阶段的伟大胜利，实现“两个一百年”奋斗目标、实现中华民族伟大复兴的中国梦，具有十分重要的指导意义。</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); font-size: 16px; font-family: 楷体; text-indent: 2em; display: block;">近日，中共中央文献研究室编辑了《习近平关于社会主义生态文明建设论述摘编》。本书内容，摘自习近平同志二〇一二年十一月十五日至二〇一七年九月十一日期间的讲话、报告、谈话、指示、批示、贺信等八十多篇重要文献，分七个专题，共计二百五十九段论述。其中许多论述是第一次公开发表。该书第四篇重点阐述“</span></strong><strong><span style="color: rgb(0, 0, 0); font-size: 16px; font-family: 楷体; text-indent: 2em; display: block;"><a href="http://theory.people.com.cn/n1/2018/0228/c417224-29838705.html" target="_blank" style="color: rgb(0, 0, 0); text-decoration-line: none;">环境保护和治理要以解决损害群众健康突出环境问题为重点</a>”，部分精彩论述如下：</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n/2013/0411/c64094-21093668.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>要坚持标本兼治、常抓不懈，从影响群众生活最突出的事情做起，既下大气力解决当前突出问题，又探索建立长久管用、能调动各方面积极性的体制机制，改善环境质量，保护人民健康，让城乡环境更宜居、人民生活更美好。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在海南考察工作结束时的讲话》（2013年4月10日）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n/2013/0525/c64094-21611332.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>人民群众对环境问题高度关注，可以说生态环境在群众生活幸福指数中的地位必然会不断凸显。随着经济社会发展和人民生活水平不断提高，环境问题往往最容易引起群众不满，弄得不好也往往最容易引发群体性事件。所以，环境保护和治理要以解决损害群众健康突出环境问题为重点，坚持预防为主、综合治理，强化水、大气、土壤等污染防治，着力推进重点流域和区域水污染防治，着力推进重点行业和重点区域大气污染治理，着力推进颗粒物污染防治，着力推进重金属污染和土壤污染综合治理，集中力量优先解决好细颗粒物（PM2.5）、饮用水、土壤、重金属、化学品等损害群众健康的突出环境问题。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在十八届中央政治局第六次集体学习时的讲话》（2013年5月24日）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>严格执行环保、安全、能耗等市场准入标准，淘汰一批落后产能。淘汰落后产能态度要坚决、步子要稳妥。对破坏生态环境、大量消耗资源、严重影响人民群众身体健康的企业，要坚决关闭淘汰。如果破坏生态环境，即使是有需求的产能也要关停，特别是群众意见很大的污染产能更要“一锅端”。对一些偷排“红汤黄水”、搞得大量鱼翻白肚皮的企业，决不能心慈手软，要坚决叫停。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在十八届中央政治局常委会会议上关于化解产能过剩的讲话》（2013年9月22日）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n/2014/0227/c64094-24476753.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>要坚持标本兼治和专项整治并重、常态治理和应急减排协调、本地治污和区域协作相互促进原则，多策并举，多地联动，全社会共同行动，聚焦燃煤、机动车、工业、扬尘四大重点领域，集中实施压减燃煤、控车减油、治污减排、清洁降尘措施。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在北京市考察工作结束时的讲话》（2014年2月26日）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n/2014/1212/c64094-26193640.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>北京亚太经合组织领导人非正式会议期间，出现了“APEC蓝”。这次压力测试证明，只要有关方面携手努力、下大决心，生态环境是可以治理好的，不是什么绝症。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在中央经济工作会议上的讲话》（2014年12月9日）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n/2014/1215/c64094-26206052.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>解决好厕所问题在新农村建设中具有标志性意义，要因地制宜做好厕所下水道管网建设和农村污水处理，不断提高农民生活质量。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——在江苏考察工作时的讲话（2014年12月13日、14日），《人民日报》2014年12月15日</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n1/2015/1223/c64094-27963704.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>过去很长一段时间，我们城市工作指导思想不太重视人居环境建设，重建设、轻治理，重速度、轻质量，重眼前、轻长远，重发展、轻保护，重地上、轻地下，重新城、轻老城。现在，人民群众对城市宜居生活的期待很高，城市工作要把创造优良人居环境作为中心目标，努力把城市建设成为人与人、人与自然和谐共处的美丽家园。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在中央城市工作会议上的讲话》（2015年12月20日）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n1/2016/0429/c64094-28313167.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>要因地制宜搞好农村人居环境综合整治，改变农村许多地方污水乱排、垃圾乱扔、秸秆乱烧的脏乱差状况，给农民一个干净整洁的生活环境。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在农村改革座谈会上的讲话》（2016年4月25日）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>良好的生态环境是人类生存与健康的基础。经过三十多年快速发展，我国经济建设取得了历史性成就，同时也积累了不少生态环境问题，其中不少环境问题影响甚至严重影响群众健康。老百姓长期呼吸污浊的空气、吃带有污染物的农产品、喝不干净的水，怎么会有健康的体魄？</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在全国卫生与健康大会上的讲话》（2016年8月19日）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>绿水青山不仅是金山银山，也是人民群众健康的重要保障。对生态环境污染问题，各级党委和政府必须高度重视，要正视问题、着力解决问题，而不要去掩盖问题。群众天天生活在环境之中，对生态环境问题采取掩耳盗铃的办法是行不通的。党中央对生态环境保护高度重视，不仅制定了一系列文件、提出了明确要求，而且组织开展了环境督察，目的就是要督促大家负起责任，加紧把生态环境保护工作做好。要按照绿色发展理念，实行最严格的生态环境保护制度，建立健全环境与健康监测、调查、风险评估制度，重点抓好空气、土壤、水污染的防治，加快推进国土绿化，治理和修复土壤特别是耕地污染，全面加强水源涵养和水质保护，综合整治大气污染特别是雾霾问题，全面整治工业污染源，切实解决影响人民群众健康的突出环境问题。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在全国卫生与健康大会上的讲话》（2016年8月19日）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n1/2016/1217/c64094-28956616.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>当前，老百姓对农产品供给的最大关切是吃得安全、吃得放心。农业供给侧结构性改革要围绕这个问题多做文章。要把增加绿色优质农产品供给放在突出位置，狠抓农产品标准化生产、品牌创建、质量安全监管，推动优胜劣汰、质量兴农。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在中央经济工作会议上的讲话》(2016年12月14日)</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n1/2016/1222/c64094-28967807.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>人民群众关心的问题是什么？是食品安不安全、暖气热不热、雾霾能不能少一点、河湖能不能清一点、垃圾焚烧能不能不有损健康、养老服务顺不顺心、能不能租得起或买得起住房，等等。相对于增长速度高一点还是低一点，这些问题更受人民群众关注。如果只实现了增长目标，而解决好人民群众普遍关心的突出问题没有进展，即使到时候我们宣布全面建成了小康社会，人民群众也不会认同。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在中央财经领导小组第十四次会议上的讲话》（2016年12月21日）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n1/2016/1222/c64094-28967807.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>普遍推行垃圾分类制度。这项工作关系十三亿多人生活环境改善，关系垃圾能不能减量化、资源化、无害化处理，关系垃圾处理中的“邻避”困局能不能从根本上破解。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n1/2016/1222/c64094-28967807.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>目前，垃圾数量增加迅速，传统填埋方式处理空间不足，而采取清洁的焚烧方式普遍受到“邻避”干扰，重要原因是没有普遍建立垃圾分类制度，垃圾分类试点试行十六年基本上仍在原地踏步。发达国家普遍实行垃圾分类制度。要研究总结浙江等地的好经验，加快在全国推广。要加快建立分类投放、分类收集、分类运输、分类处理的垃圾处理系统，形成以法治为基础、政府推动、全民参与、城乡统筹、因地制宜的垃圾分类制度，提高垃圾分类制度覆盖范围。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><a href="http://cpc.people.com.cn/n1/2016/1222/c64094-28967807.html" target="_blank" style="font-size: 16px; text-decoration: underline; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>国家发展改革委制定了生活垃圾强制分类制度的方案，发布后各地方要认真贯彻落实。要加快研究制定生活垃圾强制分类制度的法律，鼓励有条件的地区先行制定地方性法规，像生态文明试验区、北京上海这类国际性大都市、各地新城新区等就应该向国际先进水平看齐，率先建立生活垃圾强制分类制度，为全国作出表率。要加强考核评价，建立健全激励机制，对做得好的地区要表扬，做得差的要批评。党政军机关以及学校、医院等公共机构要率先实施垃圾分类制度。要增强文明素质教育，把垃圾分类知识纳入国民教育体系，从幼儿园抓起，培养全社会良好习惯。要加强生活垃圾“四分类”处理的系统性设施建设。各地在编制市县空间规划中，要对垃圾焚烧厂提早布局、明确厂址，破解“邻避”困局。</strong></span></a></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(255, 0, 0); text-indent: 2em; display: block;">——《在中央财经领导小组第十四次会议上的讲话》（2016年12月21日）</span></strong></span></p><p><br/></p>', '习近平：如果破坏生态环境，即使是有需求的产能也要关停', null, null, null, null, '20180323152158', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '6', '1', '1', '1', '1', null, '20180323152158', null, '20180323172011', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('287', '改革风劲帆正满', null, null, '文章来源至上海飞机制造有限公司', null, null, null, null, '20180427213842', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '0', '0', '0', '0', '0', '11', '1', '1', '1', '1', null, '20180427213842', null, '20180427214536', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('286', '改革风劲帆正满', null, '<section style="box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="text-align: center; color: rgb(148, 63, 39); font-size: 15px; box-sizing: border-box;"><p style="box-sizing: border-box;">关注上飞的小伙伴们，</p><p style="box-sizing: border-box;">是否记得一周前给大家透露的上飞“大动作”？</p>回忆专用链接<img src="https://mmbiz.qpic.cn/mmbiz_png/XsCHukueuAKjBySYbALgKWnb1JQkTDVxpqoz7dHI1xicKKZMkxLPhTh8ctOgVOjt2ic5yeTKKOxCkEL7NJD9icTgg/640?wx_fmt=png&wxfrom=5&wx_lazy=1"/></section><section style="text-align: center; color: rgb(148, 63, 39); font-size: 15px; box-sizing: border-box;"><a href="http://mp.weixin.qq.com/s?__biz=MzA3NTA1MDMxNw==&mid=2652823037&idx=1&sn=99d189bbe712d1834136800c11316848&chksm=849c01dfb3eb88c9d49e2e3481eacba928432f85731a20e95a8242553ee0019c50e84b214fbc&scene=21#wechat_redirect" target="_blank">厉害了！上飞亮出了这些“大动作</a><span style="color: rgb(0, 122, 170);">”</span><p style="box-sizing: border-box;">破解难题、激发活力，</p><p style="box-sizing: border-box;">今天要聚焦的，</p><p style="box-sizing: border-box;">就是其中的一个重磅专题，</p><p style="box-sizing: border-box;"><span style="color: rgb(148, 0, 11); box-sizing: border-box;"><strong style="box-sizing: border-box;">全面深化改革</strong>。</span></p></section></section></section><p><section style="box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="box-sizing: border-box;"><p style="box-sizing: border-box;"><br/></p></section></section></section><section style="box-sizing: border-box;"><section style="text-align: center; margin-top: 10px; margin-bottom: 10px; box-sizing: border-box;"><section style="width: 2.25em; height: 2.25em; border-top-color: rgb(132, 60, 21); border-left-color: rgb(132, 60, 21); border-top-width: 5px; border-left-width: 5px; border-top-style: solid; border-left-style: solid; box-sizing: border-box; transform: rotate(0deg); -webkit-transform: rotate(0deg); -moz-transform: rotate(0deg); -o-transform: rotate(0deg);"></section><section style="margin-top: -2.25em; box-sizing: border-box;"><section style="padding: 10px; box-sizing: border-box; background-color: rgb(242, 242, 242);"><section style="box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="padding: 10px; text-align: justify; color: rgb(106, 106, 106); font-size: 15px; box-sizing: border-box;"><p style="white-space: normal; box-sizing: border-box;">4月27日，上飞公司召开全面深化改革领导小组第1次会议，传达和学习中国商飞公司全面深化改革领导小组会议精神，讨论研究上飞公司2018年全面深化改革方案，听取并讨论上飞公司组织机构改革方案。上飞公司董事长、党委书记、全面深化改革领导小组组长魏应彪主持会议。副总经理余泽民、卢小安，党委副书记任彬，纪委书记张海勇，副总经理童懿，公司高管及相关部门负责人参加会议。</p></section></section></section></section></section></section></section><section style="box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="box-sizing: border-box;"><p style="box-sizing: border-box;"><br/></p></section></section></section><section style="box-sizing: border-box;"><section style="text-align: center; margin-top: 10px; margin-bottom: 10px; box-sizing: border-box;"><section style="overflow: hidden !important; vertical-align: middle; display: inline-block; max-width: 100%; box-sizing: border-box;"><img src="https://mmbiz.qpic.cn/mmbiz_jpg/XsCHukueuAKjBySYbALgKWnb1JQkTDVxjD41O2gWEtvqZz4oDjQCS7pLliasTiaIiat8M8PJW64kZMLDtnQVULFjw/640?wx_fmt=jpeg&wxfrom=5&wx_lazy=1"/></section></section></section><section style="box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="box-sizing: border-box;"><p style="box-sizing: border-box;"><br/></p></section></section></section><section style="box-sizing: border-box;"><section style="margin-top: 10px; margin-bottom: 10px; box-sizing: border-box;"><section style="padding-top: 2px; padding-bottom: 2px; box-sizing: border-box;"><section style="height: 4px; margin-top: -3px; float: left; box-sizing: border-box; transform: rotate(0deg); background-color: rgb(254, 255, 255); -webkit-transform: rotate(0deg); -moz-transform: rotate(0deg); -o-transform: rotate(0deg);"><section style="border-radius: 100%; width: 4px; height: 4px; float: left; box-sizing: border-box; background-color: rgb(132, 60, 21);"></section><section style="border-radius: 100%; width: 4px; height: 4px; margin-left: 0.5em; float: left; box-sizing: border-box; background-color: rgb(132, 60, 21);"></section><section style="border-radius: 100%; width: 4px; height: 4px; margin-left: 0.5em; float: left; box-sizing: border-box; background-color: rgb(132, 60, 21);"></section><section style="border-radius: 100%; width: 4px; height: 4px; margin-left: 0.5em; float: left; box-sizing: border-box; background-color: rgb(132, 60, 21);"></section><section style="border-radius: 100%; width: 4px; height: 4px; margin-left: 0.5em; float: left; box-sizing: border-box; background-color: rgb(132, 60, 21);"></section></section><section style="border-color: rgb(132, 60, 21); margin-top: -2px; border-top-width: 1px; border-top-style: solid; box-sizing: border-box;"></section><section style="padding: 10px; width: 100%; box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="text-align: justify; color: rgb(106, 106, 106); font-size: 15px; box-sizing: border-box;"><p style="clear: none; white-space: normal; box-sizing: border-box;">在听取与会人员讨论意见的基础上，魏应彪强调，上飞公司全面深化改革是一项复杂、系统、长远的工程，要处理好改革、发展、稳定三者关系，以稳中求进为基调，整体要体现集约性原则。谋定而后动，全面深化改革领导小组第1次会议旨在广泛统一认识，听取意见，形成统一思想。</p></section></section></section></section><section style="width: 100%; text-align: right; box-sizing: border-box;"><section style="height: 4px; margin-top: -2px; float: right; box-sizing: border-box; transform: rotate(0deg); background-color: rgb(254, 255, 255); -webkit-transform: rotate(0deg); -moz-transform: rotate(0deg); -o-transform: rotate(0deg);"><section style="border-radius: 100%; width: 4px; height: 4px; float: left; box-sizing: border-box; background-color: rgb(132, 60, 21);"></section><section style="border-radius: 100%; width: 4px; height: 4px; margin-left: 0.5em; float: left; box-sizing: border-box; background-color: rgb(132, 60, 21);"></section><section style="border-radius: 100%; width: 4px; height: 4px; margin-left: 0.5em; float: left; box-sizing: border-box; background-color: rgb(132, 60, 21);"></section><section style="border-radius: 100%; width: 4px; height: 4px; margin-left: 0.5em; float: left; box-sizing: border-box; background-color: rgb(132, 60, 21);"></section><section style="border-radius: 100%; width: 4px; height: 4px; margin-left: 0.5em; float: left; box-sizing: border-box; background-color: rgb(132, 60, 21);"></section></section><section style="clear: both; box-sizing: border-box;"></section><section style="border-color: rgb(132, 60, 21); margin-top: -2px; margin-bottom: 2px; border-top-width: 1px; border-top-style: solid; box-sizing: border-box;"><br/></section></section></section></section></section><section style="box-sizing: border-box;"><section style="box-sizing: border-box; background-color: rgb(255, 255, 255);"><section style="box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="color: rgb(106, 106, 106); font-size: 15px; box-sizing: border-box;"><p style="box-sizing: border-box;">针对全面深化改革后续工作，魏应彪指出：</p></section></section></section><section style="box-sizing: border-box;"><section style="padding-left: 15px; margin-top: 10px; margin-right: 0%; margin-left: 0%; box-sizing: border-box;"><section style="width: 95%; vertical-align: top; display: inline-block; box-sizing: border-box;"><section style="border-radius: 100%; border: 1px solid rgb(249, 110, 87); width: 1em; height: 1em; margin-top: 1.5em; margin-bottom: -2em; margin-left: -0.5em; float: left; display: inline-block; box-sizing: border-box; background-color: rgb(249, 110, 87);"></section><section style="height: 1.2em; border-left-color: rgb(249, 110, 87); border-left-width: 1px; border-left-style: solid; box-sizing: border-box;"></section><section style="padding-bottom: 0.5em; border-left-color: rgb(249, 110, 87); border-left-width: 1px; border-left-style: solid; box-sizing: border-box;"><section style="padding-top: 8px; padding-left: 15px; vertical-align: middle; box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="margin-top: -10px; margin-right: 0%; margin-left: 0%; box-sizing: border-box;"><section style="text-align: justify; color: rgb(106, 106, 106); padding-top: 5px; font-size: 15px; box-sizing: border-box;"><p style="clear: none; white-space: normal; box-sizing: border-box;">要梳理会议讨论意见和建议，积极听取相关业务部门意见，并在此基础上继续完善方案。</p></section></section></section></section></section></section></section></section><section style="box-sizing: border-box;"><section style="padding-left: 15px; margin-top: -10px; margin-right: 0%; margin-left: 0%; box-sizing: border-box;"><section style="width: 95%; vertical-align: top; display: inline-block; box-sizing: border-box;"><section style="border-radius: 100%; border: 1px solid rgb(249, 110, 87); width: 1em; height: 1em; margin-top: 1.5em; margin-bottom: -2em; margin-left: -0.5em; float: left; display: inline-block; box-sizing: border-box; background-color: rgb(249, 110, 87);"></section><section style="height: 1.2em; border-left-color: rgb(249, 110, 87); border-left-width: 1px; border-left-style: solid; box-sizing: border-box;"></section><section style="padding-bottom: 0.5em; border-left-color: rgb(249, 110, 87); border-left-width: 1px; border-left-style: solid; box-sizing: border-box;"><section style="padding-top: 8px; padding-left: 15px; vertical-align: middle; box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="margin-top: -10px; margin-right: 0%; margin-left: 0%; box-sizing: border-box;"><section style="text-align: justify; color: rgb(106, 106, 106); padding-top: 5px; font-size: 15px; box-sizing: border-box;"><p style="clear: none; white-space: normal; box-sizing: border-box;">要从内控、合规、监督角度对全面深化改革方案进行系统性评审，合理规划机构改革干部配置和人员编制，充分探讨风险点，落实责任。</p></section></section></section></section></section></section></section></section><section style="box-sizing: border-box;"><section style="padding-left: 15px; margin-top: -10px; margin-right: 0%; margin-left: 0%; box-sizing: border-box;"><section style="width: 95%; vertical-align: top; display: inline-block; box-sizing: border-box;"><section style="border-radius: 100%; border: 1px solid rgb(249, 110, 87); width: 1em; height: 1em; margin-top: 1.5em; margin-bottom: -2em; margin-left: -0.5em; float: left; display: inline-block; box-sizing: border-box; background-color: rgb(249, 110, 87);"></section><section style="height: 1.2em; border-left-color: rgb(249, 110, 87); border-left-width: 1px; border-left-style: solid; box-sizing: border-box;"></section><section style="padding-bottom: 0.5em; border-left-color: rgb(249, 110, 87); border-left-width: 1px; border-left-style: solid; box-sizing: border-box;"><section style="padding-top: 8px; padding-left: 15px; vertical-align: middle; box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="margin-top: -10px; margin-right: 0%; margin-left: 0%; box-sizing: border-box;"><section style="text-align: justify; color: rgb(106, 106, 106); padding-top: 5px; font-size: 15px; box-sizing: border-box;"><p style="clear: none; white-space: normal; box-sizing: border-box;">要拉条挂账，将具体专项工作形成行动项，按计划推进、并严格考核。</p></section></section></section></section></section></section></section></section><section style="box-sizing: border-box;"><section style="padding-left: 15px; margin-top: -10px; margin-right: 0%; margin-left: 0%; box-sizing: border-box;"><section style="width: 95%; vertical-align: top; display: inline-block; box-sizing: border-box;"><section style="border-radius: 100%; border: 1px solid rgb(249, 110, 87); width: 1em; height: 1em; margin-top: 1.5em; margin-bottom: -2em; margin-left: -0.5em; float: left; display: inline-block; box-sizing: border-box; background-color: rgb(249, 110, 87);"></section><section style="height: 1.2em; border-left-color: rgb(249, 110, 87); border-left-width: 1px; border-left-style: solid; box-sizing: border-box;"></section><section style="padding-bottom: 0.5em; border-left-color: rgb(249, 110, 87); border-left-width: 1px; border-left-style: solid; box-sizing: border-box;"><section style="padding-top: 8px; padding-left: 15px; vertical-align: middle; box-sizing: border-box;"><section style="box-sizing: border-box;"><section style="margin-top: -10px; margin-right: 0%; margin-left: 0%; box-sizing: border-box;"><section style="text-align: justify; color: rgb(106, 106, 106); padding-top: 5px; font-size: 15px; box-sizing: border-box;"><p style="clear: none; white-space: normal; box-sizing: border-box;">全面深化改革领导小组要针对十个专项改革方向定期听取汇报，形成精干高效的组织架构，以支持公司发展。</p></section></section></section></section></section></section></section></section></section></section></p><p><br/></p>', '
INSERT INTO "public"."information" VALUES ('288', '改革风劲帆正满', null, null, '', null, null, null, null, '20180427214650', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '0', '0', '0', '0', '0', '3', '1', '1', '1', '1', null, '20180427214650', null, null, '1', '2', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('214', '民进北京市委：用“互联网+共享停车”破解停车难', null, '<h3 style="margin: 0px; padding: 0px 0px 20px; font-size: 12px; font-weight: normal; text-align: center; color: rgb(74, 74, 74); font-family: 瀹嬩綋; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>2018年01月26日14:00&nbsp;&nbsp;&nbsp;&nbsp;来源：</strong></span><a href="http://dzb.rmzxb.com/index.aspx?date=2018-01-26" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>人民政协报</strong></span></a></h3><h4 style="margin: 0px; padding: 0px 0px 10px; font-weight: normal; font-size: 12px; color: rgb(74, 74, 74); font-family: 瀹嬩綋; white-space: normal; background-color: rgb(255, 255, 255);"></h4><p style="margin-top: 0px; margin-bottom: 0px; padding: 8px 0px; line-height: 30.8px; font-size: 14px; text-indent: 2em;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>机动车保有量577.1万辆，备案经营性停车位1955067个，正式施划的停车位400万个，中心城区停车位缺口高达85万个。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 8px 0px; line-height: 30.8px; font-size: 14px; text-indent: 2em;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>今年的北京市两会，民进北京市委提交的一份关于破解北京市停车难问题的提案上，这几个数字触目惊心。“停车难是北京市交通体系管理面临的关键性难题，是影响人民群众获得感幸福感的重要社会和民生问题，必须更好地加以解决，建议在政府有效支持下，创新思维，将发展‘互联网+共享停车’作为重要的破解手段。”提案执笔人、民进会员、中国交通运输协会副秘书长倪玮表示。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 8px 0px; line-height: 30.8px; font-size: 14px; text-indent: 2em;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>倪玮口中的“互联网+共享停车”，是能够充分利用智能移动终端和电子支付工具，通过错时共享，实现全市闲置、闲时停车资源随机、随时、随地共享和高效整合的互联网大数据技术，从而在一定程度上盘活现有停车资源，提高停车位利用效率。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 8px 0px; line-height: 30.8px; font-size: 14px; text-indent: 2em;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>事实上，北京市已经充分认识到错时共享停车的意义。部分企事业单位已经在属地街道办事处和区相关部门的统筹协调下，与周边居民实行错时共享停车，并取得了较好效果。同时，“互联网+共享停车”展露的商机，也已吸引了众多社会资本的参与。“但总体而言，现有的‘互联网+共享停车’基本上处于摸索阶段，还存在诸多问题。”民进北京市委议政处相关负责人告诉记者。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 8px 0px; line-height: 30.8px; font-size: 14px; text-indent: 2em;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“比如，共享停车相关方未形成合力，各方利益尚未协调；缺乏统一的车位资源管理、计时计费系统等成型技术平台；缺乏政策支持，共享停车难以成规模发展。这些都需要政府在其初期发展阶段给予引导和扶持。”</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 8px 0px; line-height: 30.8px; font-size: 14px; text-indent: 2em;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>为此，民进北京市委建议，利用经济杠杆和先进技术两个手段，以公益思想为先导，调动全社会广泛参与，同时，坚持市场化发展原则，明确发展各方的权利、义务和责任，解决好参与各方利益关系。企业重点做市场、技术以及服务，政府负责协调业主、开发公司、物业单位等关系，建立停车征信、法规、价格体系，保证各方利益和共享约束机制与内容得到充分体现。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 8px 0px; line-height: 30.8px; font-size: 14px; text-indent: 2em;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“此外，还应发挥政府的引导与主导作用，将‘互联网+共享停车’作为‘互联网+公共服务’的延伸，纳入城市静态交通建设规划中。”倪玮认为，可以通过出台政策、制定规划、提供财政资金等方式，强势推动“互联网+共享停车”，采取政府投资为主，社会投资为辅模式，引导共享停车硬件投入。并主导建设共享停车信息服务平台，对备案的车位和借助共享经济释放出来的海量新车位进行信息化管理，实施全市车位共享的有效监控。</strong></span></p><p style="margin-top: 0px; margin-bottom: 0px; padding: 8px 0px; line-height: 30.8px; font-size: 14px; text-indent: 2em;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>民进北京市委的提案中还着重提到了做好政策研究和保障机制建设，引导企业先行先试，鼓励政府资源与优势企业结合的重要性，认为政府需制定政策，扫清壁垒，放活市场。“在鼓励创新的同时，制定标准和规范，为统一共享停车市场打好基础。在此基础上，加强对共享停车发展的系统研究，特别要在收费、税务等难题上进行试点，扶持重点停车企业做强做大、支持企业兼并。”上述负责人表示。（记者 吕巍）</strong></span></p><p><br/></p>', '民进北京市委：用“互联网+共享停车”破解停车难', null, null, null, null, '20180323152645', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '3', '1', '1', '1', '1', null, '20180323152645', null, null, '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('207', '新时代属于每一个人！习近平这12个金句你记住了吗？', null, '<p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>【学习路上按】3月20日上午，十三届全国人大一次会议在北京人民大会堂举行闭幕会。中华人民共和国主席习近平发表重要讲话。在习近平的讲话中，“人民”一词被多次提及，“学习路上”根据直播文字整理，<span style="font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; font-size: 16px; text-indent: 2em;">带您回顾习近平对人民都说了哪些“知心话”。</span></strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; text-align: center;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><img alt="" src="http://scgh.gobestsoft.com:18080/ueditor/jsp/upload/image/20180323/1521789524356084659.jpg"/></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; text-align: center;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); font-size: 16px; font-family: 楷体_gb2312;">（国家主席习近平在十三届全国人大一次会议闭幕会上发表重要讲话，讲话中“人民”一词被多次提及。）</span></strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>我将一如既往 做人民的勤务员</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>担任中华人民共和国主席这一崇高职务，使命光荣，责任重大。我将一如既往，忠实履行宪法赋予的职责，忠于祖国，忠于人民，恪尽职守，竭尽全力，勤勉工作，赤诚奉献，做人民的勤务员，接受人民监督，决不辜负各位代表和全国各族人民的信任和重托！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>人民是历史的创造者，人民是真正的英雄</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>人民是历史的创造者，人民是真正的英雄。波澜壮阔的中华民族发展史是中国人民书写的！博大精深的中华文明是中国人民创造的！历久弥新的中华民族精神是中国人民培育的！中华民族迎来了从站起来、富起来到强起来的伟大飞跃是中国人民奋斗出来的！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>有这样伟大的人民，有这样伟大的民族，有这样的伟大民族精神，是我们的骄傲</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>中国人民是具有伟大创造精神的人民。中国人民是具有伟大奋斗精神的人民。中国人民是具有伟大团结精神的人民。中国人民是具有伟大梦想精神的人民。有这样伟大的人民，有这样伟大的民族，有这样的伟大民族精神，是我们的骄傲，是我们坚定中国特色社会主义道路自信、理论自信、制度自信、文化自信的底气，也是我们风雨无阻、高歌行进的根本力量！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>中国人民自古就明白，世界上没有坐享其成的好事，要幸福就要奋斗</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>中国人民自古就明白，世界上没有坐享其成的好事，要幸福就要奋斗。今天，中国人民拥有的一切，凝聚着中国人的聪明才智，浸透着中国人的辛勤汗水，蕴涵着中国人的巨大牺牲。我相信，只要13亿多中国人民始终发扬这种伟大奋斗精神，我们就一定能够达到创造人民更加美好生活的宏伟目标！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>团结就是力量，团结才能前进，一个四分五裂的国家不可能发展进步</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>中国人民从亲身经历中深刻认识到，团结就是力量，团结才能前进，一个四分五裂的国家不可能发展进步。我相信，只要13亿多中国人民始终发扬这种伟大团结精神，我们就一定能够形成勇往直前、无坚不摧的强大力量！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>人民有信心，国家才有未来，国家才有力量</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>人民有信心，国家才有未来，国家才有力量。中国特色社会主义进入了新时代，勤劳勇敢的中国人民更加自信自尊自强。中国这个古老而又现代的东方大国朝气蓬勃、气象万千，中国特色社会主义道路、理论、制度、文化焕发出强大生机活力，奇迹正在中华大地上不断涌现。我们对未来充满信心。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>路虽然还很长，但时间不等人，容不得有半点懈怠</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>把蓝图变为现实，是一场新的长征。路虽然还很长，但时间不等人，容不得有半点懈怠。我们决不能安于现状、贪图安逸、乐而忘忧，必须不忘初心、牢记使命、奋发有为，努力创造属于新时代的光辉业绩！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>增强香港、澳门同胞的国家意识和爱国精神</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>我们要全面准确贯彻“一国两制”、“港人治港”、“澳人治澳”、高度自治的方针，严格依照宪法和基本法办事，支持特别行政区政府和行政长官依法施政、积极作为，支持香港、澳门融入国家发展大局，增强香港、澳门同胞的国家意识和爱国精神，维护香港、澳门长期繁荣稳定。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>中国人民有足够的能力挫败一切分裂国家的活动！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>在这个民族大义和历史潮流面前，一切分裂祖国的行径和伎俩都是注定要失败的，都会受到人民的谴责和历史的惩罚！中国人民有坚定的意志、充分的信心、足够的能力挫败一切分裂国家的活动！中国人民和中华民族有一个共同信念，这就是：我们伟大祖国的每一寸领土都绝对不能也绝对不可能从中国分割出去！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>只有那些习惯于威胁他人的人，才会把所有人都看成是威胁</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>中国决不会以牺牲别国利益为代价来发展自己，中国发展不对任何国家构成威胁，中国永远不称霸、永远不搞扩张。只有那些习惯于威胁他人的人，才会把所有人都看成是威胁。对中国人民为人类和平与发展作贡献的真诚愿望和实际行动，任何人都不应该误读，更不应该曲解。人间自有公道在！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>中国共产党要永远做中国人民和中华民族的主心骨！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>中国共产党要担负起领导人民进行伟大社会革命的历史责任，必须勇于进行自我革命，坚持立党为公、执政为民，深入推进全面从严治党，坚决扫除一切消极腐败现象，始终与人民心心相印、与人民同甘共苦、与人民团结奋斗，永远保持马克思主义执政党本色，永远走在时代前列，永远做中国人民和中华民族的主心骨！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>新时代属于每一个人，每一个人都是新时代的见证者、开创者、建设者</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong>新时代属于每一个人，每一个人都是新时代的见证者、开创者、建设者。只要精诚团结、共同奋斗，就没有任何力量能够阻挡中国人民实现梦想的步伐！<span style="color: rgb(0, 0, 0); font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; text-indent: 2em;">我们要乘着新时代的浩荡东风，加满油，把稳舵，鼓足劲，让承载着13亿多中国人民伟大梦想的中华巨轮继续劈波斩浪、扬帆远航，胜利驶向充满希望的明天！</span></strong></span></p><p><span style="font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 0); font-size: 16px; font-family: 微软雅黑, &quot;Microsoft YaHei&quot;; text-indent: 2em;"><br/></span></strong></span></p><p><br/></p>', '新时代属于每一个人！习近平这12个金句你记住了吗？', null, null, null, null, '20180323151858', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '2', '1', '1', '1', '1', null, '20180323151857', null, '20180323172052', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('172', '王东明当选中华全国总工会主席(图/简历)', null, '<p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>中国共产党新闻网北京3月23日电 &nbsp; (记者姚茜)据《工人日报》消息，中华全国总工会第十六届执行委员会第八次全体会议22日在京召开，会议选举全国人大常委会副委员长王东明为中华全国总工会主席。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>王东明同志简历</strong></span></p><p style="margin: 10px auto; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255); text-align: center;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><img src="/ueditor/jsp/upload/image/20180323/1521786233914070469.jpg"/></strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>王东明，男，汉族，1956年7月生，辽宁宽甸人，1975年8月参加工作，1975年6月加入中国共产党，中央党校研究生学历。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>现任中共十九届中央委员，十三届全国人大常委会副委员长，四川省人大常委会主任。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1975－1978年 辽宁省桓仁县华尖子公社知青、东卜大队党支部书记</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1978－1982年 辽宁大学哲学系哲学专业学习</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1982－1982年 辽宁省委党校青训班学习</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1982－1983年 辽宁省锦州市太和区西郊公社党委副书记</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1983－1985年 共青团辽宁省锦州市委书记</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1985－1988年 辽宁省绥中县委副书记（正县级）</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1988－1991年 辽宁省绥中县委书记</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1991－1993年 辽宁省灯塔县委书记</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1993－1993年 辽宁省辽阳市副市长</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1993－1994年 辽宁省辽阳市委常委、副市长</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1994－1996年 辽宁省委组织部副部长</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1996－1997年 辽宁省委组织部部长 （1996－1997年中央党校一年制中青年干部培训班学习）</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1997－2000年 辽宁省委常委、组织部部长 （1996－1999年中央党校研究生院在职研究生班法学专业学习）</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>2000－2002年 中央组织部部务委员（副部长级）兼干部二局局长</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>2002－2007年 中央组织部副部长</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>2007－2012年 中央机构编制委员会办公室主任</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>2012－2013年 四川省委书记</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>2013－2018年 四川省委书记、省人大常委会主任</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>2018－ 十三届全国人大常委会副委员长，中华全国总工会主席，四川省人大常委会主任 中共第十七届、十八届、十九届中央委员。第十三届全国人大常委会副委员长。第十届全国政协常务委员。</strong></span></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 128); font-size: 16px; text-indent: 2em; display: block;">相关新闻</span></strong></span></p><hr/><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><a href="http://renshi.people.com.cn/n1/2018/0321/c139617-29880713.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">一日内五省委书记调整 31省区市党委书记配齐</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><a href="http://renshi.people.com.cn/n1/2018/0322/c139617-29883300.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">五省份党委书记同日调整 省委书记履新说了啥？</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><a href="http://renshi.people.com.cn/n1/2018/0321/c139617-29880940.html" target="_blank" style="text-decoration: underline; text-indent: 2em; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">聂辰席任中宣部副部长、国家广播电视总局局长、党组书记</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><a href="http://renshi.people.com.cn/n1/2018/0322/c139617-29882560.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 128); font-size: 16px; text-indent: 2em; display: block;">刘结一任中共中央台办、国务院台办主任</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><a href="http://renshi.people.com.cn/n1/2018/0322/c139617-29882650.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="color: rgb(0, 0, 128); font-size: 16px; text-indent: 2em; display: block;">新组建的国家监察委副主任和委员名单公布</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><a href="http://renshi.people.com.cn/n1/2018/0322/c139617-29882841.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">慎海雄任中央广播电视总台台长</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><a href="http://renshi.people.com.cn/n1/2018/0322/c139617-29882753.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">文化和旅游部组建 领导班子成员名单公布</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><a href="http://renshi.people.com.cn/n1/2018/0322/c139617-29882903.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">重新组建后的司法部领导班子成员名单公布</span></strong></span></a></p><p style="margin: 10px auto; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; white-space: normal; background-color: rgb(255, 255, 255);"><a href="http://renshi.people.com.cn/n1/2018/0322/c139617-29882867.html" target="_blank" style="text-decoration: underline; font-size: 16px; color: rgb(0, 0, 0);"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><span style="font-size: 16px; color: rgb(0, 0, 128);">郭树清任中国银保监会主席</span></strong></span></a></p><p><br/></p>', '王东明当选中华全国总工会主席(图/简历)', null, null, null, null, '20180323142417', null, null, null, '0', '0', '1', null, '0', '0', null, null, null, '83', '0', '0', '1', '0', '7', '1', '1', '1', '1', null, '20180323142417', null, '20180424145823', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('233', '会场突变考场，450多名机关党务干部接受“随堂测试”', null, '<p style="white-space: normal;"><span style="color: rgb(0, 0, 0);"><strong>原标题：会场突变考场，450多名机关党务干部接受“随堂测试”</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“今天会议议程全部结束。请大家留步，我们接下来进行一场机关党务干部应知应会知识测试。”2月22日下午，全省机关党的工作暨纪检工作会议结束后，省委省直工委副书记唐飞的一番话，让正准备离开会场的450多名机关党务干部大感意外。没有事先通知，没有提前准备，会场就这样变成了考场。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“党的十九大精神的灵魂和主线是什么？”“‘两个坚决维护’的内容是什么？”“新时代党的建设总要求是什么？”……测试卷上共有10道题目，考试时间10分钟，分值为100分。“测试题目和平时工作紧密结合，都属应知应会。”唐飞说。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　偌大的考场异常安静、笔声沙沙。大部分“考生”提笔答题，10分钟不到就已交了卷，也有少数“考生”低头思考、反复推敲。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“这样的突击测试头一回遇到，一点准备都没有。”走出“考场”，省司法厅机关党委专职副书记黄富献说，测试形式新颖，内容紧贴实际，考的都是机关党务干部的基本功，考不好，那实在有点不称职。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　许昌市委市直工委书记王永波说，打铁必须自身硬。机关党务干部只有真正学懂弄通习近平新时代中国特色社会主义思想和十九大精神，练就过硬的专业素养、专业本领，才能扎扎实实做好机关党务工作。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　考试结果显示，参加答题的机关党务干部成绩平均在90分以上。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　为什么要进行突击测试？省委省直工委常务副书记王忠梅表示，机关的共产党员最集中、执政骨干最集中、权力和责任也最集中。机关党务工作者的素质和能力，对提升机关党建质量至关重要。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“这次考试释放出了大学习、大提高的强烈信号，传导了责任和压力。”王忠梅表示，省委省直工委将在全省各级机关中开展“大学习、大培训、大竞赛”活动，推动学习往深里走、往实里走、往心里走，让机关党员干部真正学在前列、干在实处。（记者冯芸 通讯员翟道武 凌巍）</strong></span></p><p><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '会场突变考场，450多名机关党务干部接受“随堂测试”', null, null, null, null, '20180323155042', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '4', '1', '1', '1', '1', null, '20180323155042', null, '20180323173649', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('181', '又踏层峰望眼开', null, '<p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　这是推进国家治理体系和治理能力现代化的深刻变革。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　3月21日，《深化党和国家机构改革方案》全文对外公布。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　此前，方案中涉及国务院机构改革的内容已由全国人大审议通过，《中共中央关于深化党和国家机构改革的决定》也已公布。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　出乎预料、前所未有、全面变革、深刻重构……海内外对这次机构改革给予了高度评价。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党和国家机构大力度调整改革，充分体现了以习近平同志为核心的党中央治国理政的历史担当和全面深化改革的深谋远虑，必将为“两个一百年”奋斗目标和中华民族伟大复兴中国梦的实现提供有力制度保障。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一条红线贯穿始终——坚持和加强党的全面领导，是深化党和国家机构改革的根本保证和首要任务。习近平总书记亲自担任文件起草组组长</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　光明前景前所未有，艰巨挑战前所未有。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　新时代中国特色社会主义发展的新任务，对加强党的领导和形成科学有效的党和国家管理体制提出迫切要求。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这是勇于担当、审时度势的重大决策——</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党和国家机构职能体系是中国特色社会主义制度的重要组成部分，是我们党治国理政的重要保障。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“党政机构属于上层建筑，必须适应经济基础的要求。经济不断发展，社会不断进步，人民生活不断改善，上层建筑就要适应新的要求不断进行改革。”习近平总书记指出。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　1981年以来，党中央部门进行了4次改革，国务院机构进行了7次改革，逐步建立起具有我国特点的党和国家机构职能体系。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党和国家机构改革是一个过程，不会一蹴而就，也不会一劳永逸。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　步入新时代，党和国家机构设置和职能配置同统筹推进“五位一体”总体布局、协调推进“四个全面”战略布局的要求还不完全适应，同实现国家治理体系和治理能力现代化的要求还不完全适应。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一些领域党政机构重叠、职责交叉、权责脱节问题比较突出；一些政府机构设置和职责划分不够科学，职责缺位和效能不高问题凸显，政府职能转变还不到位；一些领域中央和地方机构职能上下一般粗，权责划分不尽合理……</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　面对新形势新任务，如果仍然顺着既有思维考虑问题，觉得保持现状挺好，不仅不能解决存在的突出问题，而且可能会误事。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“对深化党和国家机构改革的重要性和紧迫性，对深化党和国家机构改革方案的贯彻落实，都要放到新时代背景下、站在更高层次上来认识和把握。”习近平总书记强调。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　以习近平同志为核心的党中央以对党、对国家、对人民高度负责的态度，下定决心深化党和国家机构改革，从根本上解决这些障碍和弊端，以适应党和国家事业长远发展要求。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　时移世易，变法宜矣。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　2013年11月，党的十八届三中全会通过的《中共中央关于全面深化改革若干重大问题的决定》明确提出，统筹党政群机构改革，理顺部门职责关系。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　随着全面深化改革不断推进，深化机构改革提上议事日程。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　2015年，习近平总书记就要求中央全面深化改革领导小组对深化机构改革进行调研。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党的十九大报告强调，深化机构和行政体制改革。统筹考虑各类机构设置，科学配置党政部门及内设机构权力、明确职责。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　2017年12月11日，习近平总书记主持召开党的十九届三中全会文件起草小组第一次全体会议，宣布中央政治局常委会会议、中央政治局会议的决定：十九届三中全会专题研究深化机构改革问题。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党中央决定成立十九届三中全会文件起草组，由习近平总书记担任组长。相关文件起草工作正式启动。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这是从制度上发挥党的领导优势的重大部署——</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　治国犹如栽树，本根不摇则枝叶茂荣。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党的领导是我们制度最大的优势。只要牢牢坚持中国共产党的领导，中华民族伟大复兴就势不可挡。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“我们是中国共产党领导的社会主义国家，要根据实际需要，自觉进行机构调整和改革，以利于把我国社会主义制度优越性充分发挥出来。”习近平总书记强调。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　坚持和加强党的全面领导，是贯穿这次改革全过程的政治主题。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党的全面领导是具体的，不是空洞的、抽象的。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“从机构设置上充分发挥党领导一切工作的体制优势，提高党把方向、谋大局、定政策、促改革的能力和定力，把党的领导贯彻落实到党和国家机关履行职责的各方面各环节。”习近平总书记明确要求。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这次改革始终在以习近平同志为核心的党中央集中统一领导下进行，着眼于把党作为最高政治领导力量的地位和作用进一步制度化。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　事在四方，要在中央。加强党的全面领导，首先要加强党对涉及全局重大工作的集中统一领导。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　决定明确，强化党的组织在同级组织中的领导地位，更好发挥党的职能部门作用，统筹设置党政机构，推进党的纪律检查体制和国家监察体制改革。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这次改革优化党的组织、宣传、统战、政法、机关党建、教育培训等部门职责配置，加强归口协调职能，统筹本系统本领域工作。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　理顺党政机构关系，强化统筹协调，增强党的领导力，提高政府的执行力，打破所谓的党政界限，建立健全党中央对重大工作的决策协调机制。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“把一些存在职能交叉、工作重合的党中央和国务院部门合并或合署办公，把一些工作归口由党中央进行统筹协调，摆正和理顺了党政关系，既有利于保证党的重大决策集中高效，又有利于政府工作方向正确。”全国人大代表、国家行政学院副院长陈立说。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　文件起草组工作人员介绍，这次打破了以往机构改革大多局限于政府机构改革的做法，既横向统筹党政军群，又纵向统筹中央地方乃至基层，充分发挥党总揽全局、协调各方的优势，并使其进一步制度化。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这是积小胜为大胜、水到渠成的改革举措——</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这次深化机构改革并不是突如其来，而是在党的十八大以来全面深化改革取得一系列重要突破的基础上形成的，是一以贯之推进全面深化改革的必然结果。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　高举改革大旗，破解时代课题，是习近平总书记治国理政始终坚持的重要方法论。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　2012年12月，习近平担任总书记后首赴地方考察，便来到改革开放前沿广东，发出了深化改革开放新的宣言书、新的动员令。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　党的十八届三中全会后，习近平总书记亲自担任中央全面深化改革领导小组组长，既挂帅又出征。十八届中央深改领导小组先后召开38次会议，出台1500多项改革举措。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一些长期以来积弊甚深的领域，发生了历史性变革：</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　铁腕推动纪律检查体制改革，构筑“不能腐”的制度体系，党风政风焕然一新；大刀阔斧深化国防和军队改革，人民军队浴火重生征途如虹；力克“机关化、行政化、贵族化、娱乐化”倾向，群团工作开创新局面……</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　人们强烈感受到了以习近平同志为核心的党中央全面深化改革的坚定决心，大大增强了对党和国家发展前途的信心。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一系列改革的推进，已经广泛涉及到党和国家机构改革。这次深化机构改革，是积小成为大成的必然结果。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　经过党的十八大以来的不懈努力，党中央集中统一领导得到切实加强，各地区各部门“四个意识”明显增强，全面深化改革蹄疾步稳推进，主要领域改革主体框架基本确立，经济社会发展总体稳定。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　习近平总书记指出：深化机构改革的时机已经成熟。我们要抓住有利时机，下决心解决一批突出矛盾和问题。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　2018年2月26日至28日，党的十九届三中全会审议通过了《中共中央关于深化党和国家机构改革的决定》和《深化党和国家机构改革方案》，同意把《深化党和国家机构改革方案》的部分内容按照法定程序提交十三届全国人大一次会议审议。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　改革开放以来，党的三中全会聚焦改革形成惯例。与以往主要围绕经济体制改革不同，十九届三中全会聚焦深化机构改革。这次全会审议通过的《中共中央关于深化党和国家机构改革的决定》管大方向，《深化党和国家机构改革方案》管具体施工。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“看到这次改革方案，力度之大超出预料，有些过去有共识但没做成，有些过去想到了但做不成。”一位东部省份的省委书记感叹，这充分体现了习近平总书记的魄力、勇气、担当。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　强体魄于伟大的自我革命，必将开新局于伟大的社会革命。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一个指向愈发鲜明——贯彻以人民为中心的发展思想，改革为了人民也来自人民，文件起草过程中积极回应人民期待、广泛征求各方意见、借鉴吸纳基层有益探索</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一切为了人民，一切来自人民，一切依靠人民。秉承以人民为中心的发展思想，改革彰显以人民为中心的根本立场和价值取向。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　改革为了人民，老百姓关心什么、期盼什么，改革就抓什么、推进什么——</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　进入新时代，我国社会主要矛盾已经转化为人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾。机构职能体系必须适应人民新需求。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　习近平总书记明确要求，改革要精准对接发展所需、基层所盼、民心所向，充分回应人民期待。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　决定和方案把实现好、维护好、发展好最广大人民根本利益，充分体现在机构设置和职能配置中。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　问题是时代的声音，人民心声是改革所向。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　着眼于解决人民群众最盼最急最忧的突出问题，着力维护人民群众在经济、政治、文化、社会、生态等各方面权益。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　为改善“看病难看病贵”，新组建国家医疗保障局；为更好保护“青山绿水”、治理污染，专门组建生态环境部；为破解“几个大盖帽管不住一个破草帽”，组建国家市场监督管理总局，合并分散在多部门的监管职能……</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一位中部省份省长拿到方案立即注意到新组建的退役军人事务部。“制度层面的安排变化，凸显对军人军属权益保障的重视，将为新时代强军治军提供有力支撑。”这位省长说。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　利民之事，丝发必兴；厉民之事，毫末必去。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　着眼于满足人民群众对高质量公共服务的新需要，在教育文化、卫生健康、医疗保障、应急管理等领域加大机构调整和优化力度，组建一批新机构，完善公共服务体系；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　着眼于从群众最不满意的地方改起，针对执法不规范、不严格、不作为、乱作为等突出问题，在市场监管、生态环保、交通运输、农业等领域整合组建执法队伍，加快建立责权统一的执法体系；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　着眼于更好保障人民当家作主，推进社会主义民主政治制度化、规范化、程序化；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　着眼于努力实现让群众办事“只进一扇门”“最多跑一次”，尽可能把资源、服务、管理放到基层；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　……</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　从“为谁改”落实到“怎么改”，最考验的是突破利益纠葛、啃硬骨头的魄力和勇气。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“对党和国家事业有利的，对最广大人民有利的，该改的就要坚定不移改，这才是对历史负责、对人民负责、对国家负责、对民族负责。”习近平总书记的话掷地有声。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　改革来自人民，符合人民需要的改革方案从全面深入的调查研究、吸取各地各方面的探索经验中得来——</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　为了回应好人民期待，必须进行深入广泛的调研，全面倾听各方面的声音、充分吸取各地方的经验。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　其中，新组建的国家医疗保障局，就吸收了基层探索经验。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　福建三明，过去医保亏损严重，医患矛盾突出。几年前围绕医药、医保、医疗推进“三医联动”，获得了“药价下降、医务人员收入增加、医保扭亏为盈”三赢。如今，这一经验被方案借鉴。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“坚持问题导向，把各地区各部门各方面对机构改革的意见摸清楚，把机构设置存在的问题弄清楚。”2017年7月，习近平总书记就深化机构改革作出批示。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　中央改革办和中央编办组成10个调研组，分赴31个省区市、71个中央和国家机关部门。短短一个月，当面听取了139位省部级主要负责同志的意见和建议。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　回忆起去年8月那个炎热的下午，一位中部省份省委书记印象深刻：</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“就在省委招待所，我一个人，没带秘书，他们五个人坐对面。我写了个提纲，没想到他们听得很起劲，不回应、不插话，记得也很仔细，我就结合自己亲身经历放开了讲，起码谈了两个半小时。”</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　调查组还向657个市县的1197位党委和政府主要负责同志个人发放了问卷，收集了31个省份的深化地方机构改革调研报告。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　马不停蹄，紧锣密鼓。工作人员整理汇总了厚厚两大本、42万字各方面意见。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“有些问题共性很强，其中有一个共性问题60多位省部级主要负责人都提出了。”调研组工作人员说。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　调研抓准了问题、凝聚了共识，充分表明了改革的必要性和紧迫性。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一位部级领导甚至直言：“如果我所在的部门不被撤销，这就不是一次彻底的改革！”</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　集思广益、凝聚共识，实事求是、总结提炼。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　从寒冬时节到春回大地，本着对历史负责、对人民负责的态度，相关文件几经修改、一再完善，起草组的同志们字字斟酌、精益求精。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　仅决定就经历了框架稿、送审稿、征求意见稿、修改稿、讨论稿、再次修改稿等多个版本，几上几下、数易其稿的艰辛过程。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　2018年2月1日，中办发出通知，就决定稿征求各地各部门意见。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　2月6日，习近平总书记主持召开座谈会，听取各民主党派、全国工商联和无党派人士的意见。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　与会人士一致认为，平时看到的、听到的、想到的有关问题，在决定中都有回应有对策，切实体现了坚持以人民为中心的改革原则，必将成为一份指导性极强的纲领性文件。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　兼收并蓄，从善如流。各地各部门和党外人士提出的550条意见，文件起草组力求能吸收的尽量吸收，最终对决定稿修改171处。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　把人民获得感作为“试金石”，把人民的支持作为“发动机”，把深化党和国家机构改革同简政放权、放管结合、优化服务结合起来，切实做到人民有所呼、改革有所应。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这场以人民为中心的改革，正在书写历史，开创未来。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一个目标更加清晰——推进国家治理体系和治理能力现代化，努力形成更加成熟、更加定型的中国特色社会主义制度</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　中国特色社会主义步入新时代，全面建设社会主义现代化国家踏上新征程，必须实现国家治理体系和治理能力现代化。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　但横亘在现代化新征程上的挑战依然不少：发展质量和效益还不高，创新能力不够强，生态环境保护任重道远，社会服务体系不健全，民生领域还有不少短板，全面依法治国任务依然繁重……</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“这些问题同国家治理体系和治理能力直接或间接相关，要从根本上加以解决，就必须对体制机制和机构进行调整完善，推动经济、政治、文化、社会、生态文明领域改革持续深化，加快构建系统完备、科学规范、运行有效的党和国家机构职能体系。”习近平总书记强调。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　展开党和国家机构改革的宏大蓝图，人们发现，中国共产党立志进行以推进国家治理体系和治理能力现代化为目标的深刻变革的决心，力透纸背。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　——立足当前、聚焦今后三年，针对实现第一个百年奋斗目标，抓重点、补短板、强弱项、防风险；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　——放眼未来、着眼今后二三十年，前瞻实现第二个百年奋斗目标，重视打基础、立支柱、定架构，解决事关长远的体制机制问题。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　推进国家治理体系和治理能力现代化，改革突出系统性、全面性、重构性——</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　啃最硬的骨头，拆最牢的藩篱。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“组建”“重新组建”“优化”“不再设立”……方案中的一系列关键词，意味着党和国家机构正在发生一场前所未有的深刻变革。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“这不是小修小补，而是大刀阔斧；不是细枝末节，而是建梁架柱；不是拆东补西，而是系统重构。既立足当前又着眼长远。”一位西部省份省委书记说。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这次改革涉及的中央和国家机关部门、直属单位就超过80个。改革调整幅度之大，触及利益之深，为改革开放40年来之最。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“这不是分久必合、合久必分的循环往复，而是标本兼治、形神兼备、带有重构性的真改革，是一场伟大的自我革命。”一位全国人大代表说。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　推进国家治理体系和治理能力现代化，改革重在优化协同高效——</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　不少人注意到，以往的机构改革强调“精简”，这次改革并未突出这一点，而是强调“优化协同高效”。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　“优化就是要科学合理、权责一致，协同就是要有统有分、有主有次，高效就是要履职到位、流程通畅。”习近平总书记指出，只要这个目标达到了，该精简的就精简，该加强的就加强，不要为了精简而精简。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这次改革，确保一类事项原则上由一个部门统筹、一件事情原则上由一个部门负责，让党和国家机构设置更加科学、职能更加优化、权责更加协同、监管更加有力、运行更加高效。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　比如有关农业投资项目，过去牵涉到农业部、国家发展改革委和财政部等多个部门分段管理，如今要整合有关职责到新组建的农业农村部。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　社会各界普遍认为，这次改革将原来需要在多个部门之间流转的事情放在一个部门，极大提高决策和办事效率，避免政出多门、责任不明、推诿扯皮。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　推进国家治理体系和治理能力现代化，改革力求调动中央和地方两个积极性——</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　调动中央和地方两个积极性，一直以来是改革的重点。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　决定提出，确保集中统一领导；赋予省级及以下机构更多自主权；构建简约高效的基层管理体制；规范垂直管理体制和地方分级管理体制。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　原则坚定，措施灵活——决定明确，上级机关要优化对基层的领导方式，既允许“一对多”，由一个基层机构承接多个上级机构的任务；也允许“多对一”，由基层不同机构向同一个上级机构请示汇报。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　基层干部普遍反映，改革正在破解“上面千根线下面一根针”的问题，保证基层事情基层办、基层权力给基层、基层事情有人办，必将激发基层更大的活力，也对基层干部的能力有了更高的要求。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　推进国家治理体系和治理能力现代化，改革使政府与市场两只手定位更加清晰、协调——</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这次深化机构改革，对宏观管理、市场监管领域的机构和职能进行了大幅调整优化，以充分发挥市场和政府各自优势：</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　减少了宏观部门的微观管理事务和具体审批事项，要求把主要精力真正转到抓宏观上来，发挥战略导向作用；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　做出了市场监管体制改革顶层设计，组建国家市场监管总局，集中管理反垄断统一执法和知识产权保护；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　……</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一方面通过改革让各类市场主体有更多活力和更大空间去发展经济、创造财富，实现资源配置效益最大化和效率最优化；另一方面发挥党和政府的积极作用，管好那些市场管不了或者管不好的事情。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　各界人士一致看好这些举措，认为将极大降低制度性交易成本，为经济社会发展提供更为强大的驱动力。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　一分部署，九分落实。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　这是一张确保改革落地的时间表、路线图：</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　中央和国家机关机构改革要在2018年底前落实到位；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　省级党政机构改革方案要在2018年9月底前报党中央审批，2018年底前机构调整基本到位；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　省以下党政机构改革由省级党委统一领导，在2018年底前报党中央备案。所有地方党政机构改革任务在2019年3月底前基本完成；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　实施机构改革方案需要制定或修改法律的，要及时启动相关程序；依法依规完善党和国家机构职能，依法履行职责，依法管理机构和编制，确保改革在法治轨道上运行。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　40年前改革开放的声声春雷，唤醒了一个时代的蓬勃生机；</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　40年后机构改革的阵阵鼓点，更激发起奋进新时代的万丈豪情。</strong></span></p><p style="margin: 10px auto; text-indent: 0em; white-space: normal; padding: 0px; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>　　在以习近平同志为核心的党中央坚强领导下，我们一定能完成深化党和国家机构改革的各项任务，形成更加成熟、更加定型的中国特色社会主义制度，为决胜全面建成小康社会、加快推进社会主义现代化提供坚实支撑。</strong></span></p><p><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '又踏层峰望眼开', null, null, null, null, '20180323143344', null, null, null, '0', '2', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '1', '1', '1', '1', '1', null, '20180323143344', null, '20180323171759', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('222', '毛泽东诗词与中国故事', null, '<p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>左权，抗日战争中八路军牺牲的职务最高的指挥员。他把生命过早地献给了中国人民的解放事业，所幸他为后人留下了一沓生动鲜活的家书，才使我们永远记住这位情感细腻的威风男儿。七十多年过去了，这些家书的纸张已变成了枯黄色，字迹也淡化了许多，然而，这字里行间蕴含着的绵绵深情却永远震撼着我们。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>司令部里最繁忙的人</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>左权，原名左纪权，号叔仁，1905年生于湖南醴陵。1924年到广州，进入孙中山大元帅府军政部主办的陆军讲武学校，后转入黄埔军校第一期。1925年加入中国共产党，并被选送到苏联留学，相继进入莫斯科中山大学和伏龙芝军事学院深造。1930年奉调回国，被分配到中央苏区工作。先后担任红军军官学校一分校教育长、新12军军长、红一方面军总司令部参谋处长、红15军军长兼政委、中革军委作战局局长、红一军团参谋长等职，多次参与指挥反“围剿”作战，参加了长征。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>1937年8月，红军改编为八路军，左权被任命为八路军副参谋长。不久，他随朱德总司令、彭德怀副总司令率部东渡黄河，挺进华北，开辟抗日根据地。随后他还兼任八路军前方总部参谋长，在指挥作战和军队建设方面作出了突出贡献。特别是1940年参与领导了著名的百团大战，1941年取得保卫八路军黄崖洞兵工厂的“黄崖大捷”。1942年5月25日，在指挥八路军总部机关转移时，被敌人的炮弹击中牺牲，时年37岁。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>左权长期担任参谋长工作。著名作家刘白羽1939年春天曾在八路军总部见到左权，发现他是司令部里“最繁忙的人”，“除了重大的事由朱总司令决定之外，一般工作都是他处理”。左权牺牲后，晋察冀军区司令员兼政治委员聂荣臻在悼念左权的文章中说：“军队的一切建设, 部队的管理教育, 战斗战役的组织,一切军机的运筹帷幄, 无不精细周详, 大事不悸, 小事不忽, 在日常工作中, 尤其是敢于负责, 决非敷衍苟且之徒可比。”时任八路军一二九师政治部主任蔡树藩回忆说：“对于工作, 左权同志有着认真不懈的工作精神, 每天都要做到十五六个小时工作, 往往工作到更深人静的半夜。”抗战期间曾担任左权警卫员的陈利财回忆说：“左副参谋长的工作是非常繁忙而紧张的，每天工作在16个小时以上。有时朱总、彭总去延安开会，总部就只剩下他一个人，他从早到晚不停地忙着。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>左权读过两所军事院校，又喜欢读书，军事理论水平很高，撰写了许多关于游击战争的论著。周恩来称他“是有理论修养同时又有实践经验的军事家”。朱德评价他“在军事理论、战略战术、军事建设、参谋工作、后勤工作等方面，有极其丰富与辉煌的建树，是中国军事界不可多得的人才”。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>烽火家书寄深情</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>左权年少离家，投身军旅，戎马倥偬十余年，无暇顾及个人问题，直到34岁时在抗战前线遇到了刘志兰。刘志兰1917年生于北平，是北平师范大学的学生，参加过“一二·九”运动，1937年入党，带着弟弟刘志林一起奔赴延安参加抗战,1939年2月来到山西前线，在中央北方局妇委会工作。经八路军总司令朱德做媒，4月16日，左权与刘志兰在八路军总部驻地潞城县北村结婚。第二年5月，生下了女儿左太北。女儿出生后，一家三口度过了一段其乐融融的生活。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>然而，战争越来越残酷，日军疯狂进攻太行山根据地。八路军总部经常转移，家属随同活动有诸多不便。1940年8月30日，左权不得不把妻子和女儿送往延安。分别之前，三个人照了一张合影，当时女儿不满百日。谁也没有想到，这次分别竟是刘志兰母女与丈夫和父亲的永别。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>得知妻子和女儿平安到达延安，左权于1940年11月12日给妻子写了第一封信，之后直到21个月后牺牲，他总共给妻子写了12封信，其中有一封遗失了，保存下来11封，共1.6万字。在这些家书中，给人印象最深的就是左权对于妻子和女儿深深的爱恋。他的每封家书都用较大的篇幅来问候妻子和女儿，或表达思念，或表达关切，从学习、工作，到衣食、冷暖，可谓无微不至。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>昏黄的油灯下，左权洗去一天的征尘，看着桌旁一家三口的照片，心绪难平，遂铺开信纸，奋笔疾书：</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“聪敏活泼的太北小家伙很远的离开，长久的不能看到她，当然更增加我的悬念。我只希望你一方面照顾着太北，同时又能很好安心的学习，有便时多写几封信给我。志兰亲爱的，最近的期间内恐难见面的，相互努力工作与学习吧!”（1940年11月12日第一封）</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“延安的天气，想来一定很冷了。记得太北小家伙似很怕冷的，在砖壁那几天下雨起风天气较冷时，小家伙不就手也冰冷，鼻子不通奶也不能吃吗？现在怎样？半岁了，较前大了一些，总该好些吧!希当心些，不要冷着这个小宝贝，我俩的小宝贝。”（1940年12月23日第二封）</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>……</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>“在闲游与独坐中,有时总仿佛有你及北北与我在一块玩着、谈着。特别是北北非常调皮,一时在地下,一时爬着妈妈怀里,又由妈妈怀里转到爸爸怀里来,闹个不休,真是快乐。可惜三个人分在三起,假如在一块的话,真痛快极了。……志兰!亲爱的，别时容易见时难。分离廿一个月了，何日相聚，念念、念念。”（1942年5月22日第十一封）</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>在战友和下属的眼中，左权是足智多谋、叱咤风云的指挥员，而在家书中，他是一位体贴入微的丈夫和舐犊情深的父亲。一家三口本该享受的天伦之乐，却被残酷的战争无情地阻隔，只能靠这薄薄的信纸倾诉衷肠。这些家书长期保存在刘志兰手中，1982年5月，左权牺牲整整40年后，刘志兰把这批珍贵的家书交给了女儿左太北。左太北才从这些家书中知道父亲是多么爱她，每一封信中都会问到她的情况。她原来以为父亲就是一位铁骨铮铮的军人，没想到家书里的父亲是那么感情丰富，那么富有爱心！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>见证抗战的珍贵史料</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>左权写作这些家书时，正值抗日战争进入相持阶段，敌后战场也迎来了最为艰苦的岁月。日军抽调重兵疯狂进攻华北抗日根据地，采取“三光”政策、“囚笼”政策、“铁壁合围”、细菌战等，根据地军民遭受极大的损失。左权协助彭德怀副总司令指挥了百团大战等一系列反击作战。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>对于根据地的困难局面，左权在家书中也有具体的描述。第一封家书中说：“敌人的政策是企图变我根据地为一片焦土，见人便杀，见屋便烧，见粮食便毁，见牲畜便打，虽僻野山沟都遭受了损失，整个太北除冀西一角较好外，统均烧毁，其状极惨。”第四封家书中说：“现边区受敌重重封锁，腹地亦密布钉子，敌图化[划]边区西侧为治安区，腹地为无人区，即以最凶恶的手段实行三光政策，并村等等，以遂其澈[彻]底毁灭我边区之目的。边区现已陷入极严重的斗争环境，困难也大为增加了。”第九封家书中说：“敌人的残酷仍然如故，军队损失虽然不大，老百姓却遭殃不小。敌人新的花样就是放毒。在军队指挥机关驻地，在地方，在某些政权机关及某些群众家里，满布糜烂性毒质[物]。在我们去年的原驻地布毒不少，我及廿二号的房子都布满了。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>敌人的凶残并没有吓倒根据地军民，反而更加坚定了他们抗战的决心。“我们不管他怎样，在目前在本身工作上努力根据地之巩固军队的强大，随时准备着对付敌之北进。”“敌图改变我根据地性质的企图，也不会放松的，一切均有待我们准备在极严重极艰苦的环境中去战胜敌人。”“全区党政军民均在纷纷准备粉碎敌人的进攻，我们的工作也就更急迫更紧张些了。”</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>由于根据地遭到日寇的重重封锁，邮驿系统迭遭破坏，这些家书都是左权托人捎带至延安，交给刘志兰的，有时一两个月，有时四五个月才能送达收信人手中，真正属于“烽火连三月，家书抵万金”啊！</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>一封家书，一段历史。外敌入侵，生灵涂炭，军民奋起，保家卫国。左权家书为我们保留了一份反映敌后抗战历史的珍贵史料，这是战争亲历者的记录，是真实可信的第一手档案。左权家书同时具有重要的伦理价值，人间最为美好的夫妻爱情、父女亲情和爱国之情，凝聚在一封封家书中，默默地释放出震撼人心的力量。以左权为代表的前方将士的英勇牺牲和全国各阶层民众、海外华侨的倾力支援，共同汇聚成伟大的抗战精神，激励一代又一代中华儿女为实现中华民族伟大复兴的中国梦而努力奋斗。</strong></span></p><p style="margin: 10px auto; white-space: normal; padding: 0px; text-indent: 2em; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑;"><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong>（作者张丁为中国人民大学家书博物馆副馆长）</strong></span></p><p><span style="font-size: 16px; color: rgb(0, 0, 0);"><strong><br/></strong></span></p><p><br/></p>', '毛泽东诗词与中国故事', null, null, null, null, '20180323153651', null, null, null, '0', '0', '0', null, '0', '0', null, null, null, '83', '0', '0', '0', '0', '2', '1', '1', '1', '1', null, '20180323153650', null, '20180323174309', '1', '0', null, '0', null, null, null, null, null);
INSERT INTO "public"."information" VALUES ('302', '十分钟速读十九大报告', null, null, '', null, null, null, null, '20180427235906', null, null, null, '0', '0', '0', null, '7', '0', null, null, null, '0', '0', '0', '0', '0', '4', '1', '1', '1', '1', null, '20180427235906', null, null, '0', '1', null, '0', null, null, null, null, null);
